app/globals.css.content:
/* @import url("https://fonts.googleapis.com/css2?family=Poetsen+One&display=swap"); */

@tailwind base;
@tailwind components;
@tailwind utilities;

code {
  background-color: #f5f2f0;
  color: #353132;
  padding: 0.2em 0.4em;
  border-radius: 3px;
  font-family: "Courier New", Courier, monospace;
  font-size: 0.95em;
}

/* Hide scroll bar */
@layer utilities {
  /* Hide scrollbar for Chrome, Safari and Opera */
  .no-scrollbar::-webkit-scrollbar {
    display: none;
  }

  /* Hide scrollbar for IE, Edge and Firefox */
  .no-scrollbar {
    -ms-overflow-style: none; /* IE and Edge */
    scrollbar-width: none; /* Firefox */
  }
}

@layer base {
  /* Theme colors */
  [data-theme="anotherwrapper"] .btn-primary,
  [data-theme="anotherwrapper"] .bg-primary {
    color: hsl(var(--primary-foreground));
  }

  [data-theme="anotherwrapper"] .btn-secondary,
  [data-theme="anotherwrapper"] .bg-secondary {
    color: hsl(var(--secondary-foreground));
  }

  [data-theme="anotherwrapper"] .btn-accent,
  [data-theme="anotherwrapper"] .bg-accent {
    color: hsl(var(--accent-foreground));
  }

  :root {
    --background: 0 0% 100%;
    --foreground: 222.2 84% 4.9%;

    --card: 0 0% 100%;
    --card-foreground: 222.2 84% 4.9%;

    --popover: 0 0% 100%;
    --popover-foreground: 222.2 84% 4.9%;

    --primary: 222.2 47.4% 11.2%;
    --primary-foreground: 210 40% 98%;

    --secondary: 210 40% 96.1%;
    --secondary-foreground: 222.2 47.4% 11.2%;

    --muted: 210 40% 96.1%;
    --muted-foreground: 215.4 16.3% 46.9%;

    --accent: 0 0% 9%; /* #171717 */
    --accent-foreground: 0 0% 100%; /* White text */

    --destructive: 0 84.2% 60.2%;
    --destructive-foreground: 210 40% 98%;

    --border: 214.3 31.8% 91.4%;
    --input: 214.3 31.8% 91.4%;
    --ring: 222.2 84% 4.9%;

    --radius: 0.5rem;

    --sidebar-background: 0 0% 98%;

    --sidebar-foreground: 240 5.3% 26.1%;

    --sidebar-primary: 240 5.9% 10%;

    --sidebar-primary-foreground: 0 0% 98%;

    --sidebar-accent: 240 4.8% 95.9%;

    --sidebar-accent-foreground: 240 5.9% 10%;

    --sidebar-border: 220 13% 91%;

    --sidebar-ring: 217.2 91.2% 59.8%;
  }

  .dark {
    --background: 222.2 84% 4.9%;
    --foreground: 210 40% 98%;

    --card: 222.2 84% 4.9%;
    --card-foreground: 210 40% 98%;

    --popover: 222.2 84% 4.9%;
    --popover-foreground: 210 40% 98%;

    --primary: 210 40% 98%;
    --primary-foreground: 222.2 47.4% 11.2%;

    --secondary: 217.2 32.6% 17.5%;
    --secondary-foreground: 210 40% 98%;

    --muted: 217.2 32.6% 17.5%;
    --muted-foreground: 215 20.2% 65.1%;

    --accent: 217.2 32.6% 17.5%;
    --accent-foreground: 210 40% 98%;

    --destructive: 0 62.8% 30.6%;
    --destructive-foreground: 210 40% 98%;

    --border: 217.2 32.6% 17.5%;
    --input: 217.2 32.6% 17.5%;
    --ring: 212.7 26.8% 83.9%;
    --sidebar-background: 240 5.9% 10%;
    --sidebar-foreground: 240 4.8% 95.9%;
    --sidebar-primary: 224.3 76.3% 48%;
    --sidebar-primary-foreground: 0 0% 100%;
    --sidebar-accent: 240 3.7% 15.9%;
    --sidebar-accent-foreground: 240 4.8% 95.9%;
    --sidebar-border: 240 3.7% 15.9%;
    --sidebar-ring: 217.2 91.2% 59.8%;
  }
  /* Theme-specific accent colors */
  [data-theme="anotherwrapper"] {
    --background: 0 0% 100%;
    --foreground: 222.2 84% 4.9%;

    --primary: 240 5% 10%; /* #18181b */
    --primary-foreground: 0 0% 100%;

    --secondary: 0 0% 75%; /* #bfbfbf */
    --secondary-foreground: 0 0% 100%;

    --accent: 0 0% 9%; /* #171717 */
    --accent-foreground: 0 0% 100%;

    --destructive: 0 84.2% 60.2%;
    --destructive-foreground: 0 0% 100%;

    --muted: 210 40% 96.1%;
    --muted-foreground: 215.4 16.3% 46.9%;

    --popover: 0 0% 100%;
    --popover-foreground: 222.2 84% 4.9%;

    --card: 0 0% 100%;
    --card-foreground: 222.2 84% 4.9%;

    --border: 214.3 31.8% 91.4%;
    --input: 214.3 31.8% 91.4%;
    --ring: 222.2 84% 4.9%;
  }

  [data-theme="anotherwrapperDark"] {
    --accent: 187 29% 57%; /* #76ABAE */
    --accent-foreground: 0 0% 100%;
  }

  [data-theme="whisper"] {
    --accent: 39 46% 85%; /* #EADBC8 */
    --accent-foreground: 0 0% 0%;
  }

  [data-theme="branding"] {
    --accent: 180 48% 32%; /* #2d7676 */
    --accent-foreground: 0 0% 100%;
  }

  [data-theme="workoutpro"] {
    --accent: 140 84% 9%; /* #093119 */
    --accent-foreground: 0 0% 100%;
  }

  [data-theme="logo"] {
    --accent: 40 10% 69%; /* #B8B2A6 */
    --accent-foreground: 0 0% 0%;
  }

  [data-theme="marketing"] {
    --accent: 11 95% 75%; /* #fc9780 */
    --accent-foreground: 0 0% 0%;
  }

  [data-theme="vision"] {
    --accent: 207 36% 70%; /* #9BB8CD */
    --accent-foreground: 0 0% 0%;
  }

  [data-theme="interioresia"] {
    --accent: 15 72% 31%; /* #883c17 */
    --accent-foreground: 0 0% 100%;
  }

  [data-theme="sdxl"] {
    --accent: 0 3% 19%; /* #322C2B */
    --accent-foreground: 0 0% 100%;
  }

  [data-theme="indielogs"] {
    --accent: 225 43% 26%; /* #25305e */
    --accent-foreground: 0 0% 100%;
  }

  [data-theme="imagenmia"] {
    --accent: 39 84% 58%; /* #eeaf3a */
    --accent-foreground: 0 0% 0%;
  }

  /* Modern Stacks Dark Theme */
  .theme-stacks {
    /* Core Colors - Dark Theme */
    --bg: 10 10 15; /* #0a0a0f - Very dark background */
    --surface: 17 17 27; /* #11111b - Dark surface */
    --surface-2: 23 23 37; /* #171725 - Slightly lighter surface */
    --border: 45 45 65; /* #2d2d41 - Subtle borders */
    --fg: 240 240 245; /* #f0f0f5 - Light text */
    --muted: 140 140 160; /* #8c8ca0 - Muted text */

    /* Accent Colors - Purple/Violet Theme */
    --primary: 139 92 246; /* #8b5cf6 - Purple accent */
    --secondary: 99 102 241; /* #6366f1 - Indigo accent */
    --accent: 167 139 250; /* #a78bfa - Light purple */
    --success: 52 211 153; /* #34d399 - Success green */
    --warn: 251 191 36; /* #fbbf24 - Warning yellow */
    --destructive: 239 68 68; /* #ef4444 - Error red */

    /* Glow Colors - Purple/Violet Glows */
    --glow-primary: 139 92 246; /* #8b5cf6 */
    --glow-secondary: 99 102 241; /* #6366f1 */
    --glow-accent: 167 139 250; /* #a78bfa */
    --glow-success: 52 211 153; /* #34d399 */
    --glow-warn: 251 191 36; /* #fbbf24 */
    --glow-destructive: 239 68 68; /* #ef4444 */

    /* Focus ring color - Purple */
    --ring: 139 92 246; /* Purple focus ring */
  }
}

@layer utilities {
  /* Glow Effects - Enhanced for Dark Theme */
  .glow-primary {
    filter: drop-shadow(0 0 20px rgb(var(--glow-primary) / 0.6));
  }

  .glow-secondary {
    filter: drop-shadow(0 0 20px rgb(var(--glow-secondary) / 0.6));
  }

  .glow-accent {
    filter: drop-shadow(0 0 20px rgb(var(--glow-accent) / 0.6));
  }

  .glow-success {
    filter: drop-shadow(0 0 20px rgb(var(--glow-success) / 0.6));
  }

  .glow-warn {
    filter: drop-shadow(0 0 20px rgb(var(--glow-warn) / 0.6));
  }

  .glow-destructive {
    filter: drop-shadow(0 0 20px rgb(var(--glow-destructive) / 0.6));
  }

  /* Ring Glow Effects - Purple for Dark Theme */
  .ring-glow {
    --tw-ring-color: rgb(var(--primary) / 0.5);
    --tw-ring-shadow: 0 0 0 var(--tw-ring-offset-width) var(--tw-ring-offset-color), 
                      0 0 0 calc(2px + var(--tw-ring-offset-width)) var(--tw-ring-color),
                      0 0 20px rgb(var(--primary) / 0.4);
  }

  /* Glass Effects - Dark Theme */
  .glass {
    background: rgb(var(--surface) / 0.8);
    backdrop-filter: blur(16px);
    border: 1px solid rgb(var(--border) / 0.3);
    box-shadow: 0 0 40px rgb(var(--primary) / 0.1);
  }

  .glass-subtle {
    background: rgb(var(--surface) / 0.6);
    backdrop-filter: blur(12px);
    border: 1px solid rgb(var(--border) / 0.2);
    box-shadow: 0 0 20px rgb(var(--primary) / 0.05);
  }

  /* Vector Background - Dark with Purple Gradient */
  .bg-vector {
    background-image: 
      radial-gradient(circle at 20% 50%, rgb(var(--primary) / 0.15) 0%, transparent 50%),
      radial-gradient(circle at 80% 20%, rgb(var(--accent) / 0.12) 0%, transparent 50%),
      radial-gradient(circle at 40% 80%, rgb(var(--secondary) / 0.1) 0%, transparent 50%);
  }

  /* Animations */
  @keyframes shimmer {
    0% { background-position: -200% 0; }
    100% { background-position: 200% 0; }
  }

  @keyframes pulse-glow {
    0%, 100% { filter: drop-shadow(0 0 8px rgba(106, 166, 255, 0.45)) drop-shadow(0 0 20px rgba(106, 166, 255, 0.2)); }
    50% { filter: drop-shadow(0 0 12px rgba(106, 166, 255, 0.6)) drop-shadow(0 0 30px rgba(106, 166, 255, 0.3)); }
  }

  @keyframes fadeInUp {
    0% { 
      opacity: 0; 
      transform: translateY(30px); 
    }
    100% { 
      opacity: 1; 
