'use client'

import * as React from 'react'

export interface useCopyToClipboardProps {
  timeout?: number
}

export function useCopyToClipboard({
  timeout = 2000
}: useCopyToClipboardProps) {
  const [isCopied, setIsCopied] = React.useState<Boolean>(false)

  const copyToClipboard = (value: string) => {
    if (typeof window === 'undefined' || !navigator.clipboard?.writeText) {
      return
    }

    if (!value) {
      return
    }

    navigator.clipboard.writeText(value).then(() => {
      setIsCopied(true)

      setTimeout(() => {
        setIsCopied(false)
      }, timeout)
    })
  }

  return { isCopied, copyToClipboard }
}

lib/hooks/generateAIResponse.ts.content:
import { useRouter } from "next/navigation";
import { useState } from "react";
import { createClient } from "@/lib/utils/supabase/client";
import { type ToolConfig } from "@/lib/types/toolconfig";

export const generateAIResponse = (
  toolConfig: ToolConfig,
  userEmail: string,
  imageUrl: string | null,
  setGeneratedImage: React.Dispatch<React.SetStateAction<string | null>>
) => {
  const [loading, setLoading] = useState(false);
  const router = useRouter();

  const generateResponse = async (
    formData: { [key: string]: string },
    event: React.FormEvent<HTMLFormElement>
  ) => {
    event.preventDefault();
    setLoading(true);

    let endpoint = "/gpt/api";
    let body: { [key: string]: any } = formData;

    // Set the endpoint and body based on the tool type
    switch (toolConfig.type) {
      case "vision":
        endpoint = "/vision/api";
        body = { ...formData, imageUrl };
        break;
      case "dalle":
        endpoint = "/dalle/api";
        break;
      case "groq":
        endpoint = "/groq/api/groq";
        break;
      case "claude":
        endpoint = "/claude/api";
        break;
      case "grok":
        endpoint = "/grok/api";
        break;
    }

    try {
      const response = await fetch(endpoint, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          ...body,
          email: userEmail,
          toolPath: encodeURIComponent(toolConfig.toolPath!),
        }),
      });

      if (!response.ok) {
        throw new Error("Network response was not ok");
      }

      const responseData = await response.json();

      // If we used DALLE, fetch the generated image from Supabase
      if (toolConfig.type === "dalle") {
        const supabase = createClient();
        const { data: generations, error } = await supabase
          .from("generations")
          .select("output_data")
          .eq("id", responseData.id);

        if (error) {
          throw new Error(`Supabase fetch error: ${error.message}`);
        }

        if (generations && generations.length > 0) {
          setGeneratedImage(generations[0].output_data);
        }
      } else {
        // For navigation, use slug for Grok and id for others
        const baseUrl = toolConfig.company.appUrl.startsWith("/")
          ? toolConfig.company.appUrl.slice(1)
          : toolConfig.company.appUrl;

        const navigationPath = `/${baseUrl}/${responseData.slug}`;
        router.push(navigationPath);
      }
    } catch (error) {
      console.error("Failed to generate responses:", error);
    } finally {
      setLoading(false);
    }
  };

  return [generateResponse, loading] as const;
};

lib/hooks/generateSlug.ts.content:
import { createClient } from "@/lib/utils/supabase/server";

function slugify(text: string): string {
  return text
    .toString()
    .toLowerCase()
    .trim()
    .replace(/\s+/g, "-")
    .replace(/[^\w\-]+/g, "")
    .replace(/\-\-+/g, "-")
    .replace(/^-+/, "")
    .replace(/-+$/, "");
}

export async function generateUniqueSlug(
  title: string,
  type: string
): Promise<string> {
  const supabase = await createClient();

  const baseSlug = slugify(title);
  let slug = baseSlug;
  let counter = 0;
  let isUnique = false;

  while (!isUnique) {
    const { data, error } = await supabase
      .from("generations")
      .select("slug")
      .eq("slug", counter === 0 ? slug : `${slug}-${counter}`)
      .eq("type", type)
      .single();

    if (error?.code === "PGRST116") {
      // No results found, slug is unique
      isUnique = true;
      if (counter > 0) {
        slug = `${slug}-${counter}`;
      }
    } else if (error) {
      throw error;
    } else {
      // Slug exists, increment counter
      counter++;
    }
  }

  return slug;
}

lib/hooks/use-image-generation.ts.content:
import { useState } from "react";
import { useRouter } from "next/navigation";
import {
  ImageError,
  ImageResult,
  ProviderTiming,
  ProviderKey,
  initializeProviderRecord,
} from "@/lib/ai/image-ai";

interface UseImageGenerationReturn {
  images: ImageResult[];
  errors: ImageError[];
  timings: Record<ProviderKey, ProviderTiming>;
  failedProviders: ProviderKey[];
  isLoading: boolean;
  startGeneration: (
    prompt: string,
    providers: ProviderKey[],
    providerToModel: Record<ProviderKey, string>
  ) => Promise<void>;
  resetState: () => void;
}

export function useImageGeneration(): UseImageGenerationReturn {
  const router = useRouter();
  const [images, setImages] = useState<ImageResult[]>([]);
  const [errors, setErrors] = useState<ImageError[]>([]);
  const [timings, setTimings] = useState<Record<ProviderKey, ProviderTiming>>(
    initializeProviderRecord<ProviderTiming>()
  );
  const [failedProviders, setFailedProviders] = useState<ProviderKey[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const resetState = () => {
    setImages([]);
    setErrors([]);
    setTimings(initializeProviderRecord<ProviderTiming>());
    setFailedProviders([]);
    setIsLoading(false);
  };

  const startGeneration = async (
    prompt: string,
    providers: ProviderKey[],
    providerToModel: Record<ProviderKey, string>
  ) => {
    try {
      setIsLoading(true);
      // Initialize images array with null values
      setImages(
        providers.map((provider) => ({
          provider,
          image: null,
          modelId: providerToModel[provider],
        }))
      );

      // Clear previous state
      setErrors([]);
      setFailedProviders([]);

      // Initialize timings with start times
      const now = Date.now();
      setTimings(
        Object.fromEntries(
          providers.map((provider) => [provider, { startTime: now }])
        ) as Record<ProviderKey, ProviderTiming>
      );

      // Helper to fetch a single provider
      const generateImage = async (provider: ProviderKey, modelId: string) => {
        const startTime = now;
        console.log(
          `Generate image request [provider=${provider}, modelId=${modelId}]`
        );
        try {
          const response = await fetch("/image-ai/api", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ prompt, provider, modelId }),
          });
          const data = await response.json();
          if (!response.ok) {
            throw new Error(data.error || `Server error: ${response.status}`);
          }

          const completionTime = Date.now();
          const elapsed = completionTime - startTime;
          setTimings((prev) => ({
            ...prev,
            [provider]: {
              startTime,
              completionTime,
              elapsed,
            },
          }));

          console.log(
            `Successful image response [provider=${provider}, modelId=${modelId}, elapsed=${elapsed}ms]`
          );

          // Update image in state
          setImages((prevImages) =>
            prevImages.map((item) =>
              item.provider === provider
                ? { ...item, image: data.image ?? null, modelId }
                : item
            )
          );

          // Refresh the generations list after successful generation
          router.refresh();
        } catch (err) {
          console.error(
            `Error [provider=${provider}, modelId=${modelId}]:`,
            err
          );
          setFailedProviders((prev) => [...prev, provider]);
          setErrors((prev) => [
            ...prev,
            {
              provider,
              message:
                err instanceof Error
                  ? err.message
                  : "An unexpected error occurred",
            },
          ]);

          setImages((prevImages) =>
            prevImages.map((item) =>
              item.provider === provider
                ? { ...item, image: null, modelId }
                : item
            )
          );
        }
      };

      // Generate images for all active providers
      const fetchPromises = providers.map((provider) => {
        const modelId = providerToModel[provider];
        return generateImage(provider, modelId);
      });

      await Promise.all(fetchPromises);
    } catch (error) {
      console.error("Error fetching images:", error);
    } finally {
      setIsLoading(false);
    }
  };

  return {
    images,
    errors,
    timings,
    failedProviders,
    isLoading,
    startGeneration,
    resetState,
  };
}

lib/hooks/use-mobile.tsx.content:
import * as React from "react";

const MOBILE_BREAKPOINT = 768;

export function useIsMobile() {
  const [isMobile, setIsMobile] = React.useState<boolean | undefined>(
    undefined
  );

  React.useEffect(() => {
    const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`);
    const onChange = () => {
      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT);
    };
    mql.addEventListener("change", onChange);
    setIsMobile(window.innerWidth < MOBILE_BREAKPOINT);
    return () => mql.removeEventListener("change", onChange);
  }, []);

  return !!isMobile;
}

lib/hooks/useDebounce.ts.content:
import { useState, useEffect } from "react";

export function useDebounce<T>(value: T, delay: number): T {
  const [debouncedValue, setDebouncedValue] = useState<T>(value);

  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);

    return () => {
      clearTimeout(handler);
    };
  }, [value, delay]);

  return debouncedValue;
}

lib/hooks/useFileUpload.ts.content:
import { PutObjectCommand } from "@aws-sdk/client-s3";
import s3 from "@/lib/clients/cloudflare";
import sharp from "sharp";
import { v4 as uuidv4 } from "uuid";
import { supabase } from "@/lib/utils/supabase/service";

interface UploadOptions {
  file?: {
    arrayBuffer(): Promise<ArrayBuffer>;
    type?: string;
    name?: string;
  };
  imageUrl?: string;
  uploadPath: string;
  contentType?: string;
  fileName?: string;
  skipMetadata?: boolean;
  userId?: string;
  chatId?: string;
}

/**
 * Uploads a file or image URL to cloud storage.
 *
 * @param {UploadOptions} options - The options for file upload.
 * @returns {Promise<{url: string, path: string}>} The public URL and path of the uploaded file.
 *
 * **Functionality:**
 * - For images:
 *   - Optimizes the image using `sharp` and converts it to JPEG format.
 *   - Ignores the original file extension and saves the file with a `.jpeg` extension.
 * - For other file types (e.g., audio, PDF):
 *   - Preserves the original file's content type and extension.
 * - Generates a unique file name using UUID to prevent guessing or enumeration.
 * - Validates and sanitizes input to prevent path traversal attacks.
 * - Does not use any user-specific information in the file path to ensure privacy.
 */

export async function uploadFile({
  file,
  imageUrl,
  uploadPath,
  contentType,
  fileName,
  skipMetadata = false,
  userId,
  chatId,
}: UploadOptions) {
  try {
    let fileBuffer: Buffer;
    let finalFileName = fileName || `file-${uuidv4()}`;
    let originalName = file?.name || finalFileName;
    let fileSize = 0;

    // Sanitize uploadPath to prevent path traversal
    uploadPath = uploadPath.replace(/[^a-zA-Z0-9-_\/]/g, "");

    if (file) {
      fileBuffer = Buffer.from(await file.arrayBuffer());
      fileSize = fileBuffer.length;

      // Detect content type if not provided
      if (!contentType && "type" in file) {
        contentType = file.type;
      }

      // Check if the file is an image
      if (contentType?.startsWith("image/")) {
        // Optimize image and convert to JPEG using sharp
        fileBuffer = await sharp(fileBuffer).jpeg({ quality: 80 }).toBuffer();
        finalFileName = `${finalFileName.replace(/\.[^/.]+$/, "")}.jpeg`;
        contentType = "image/jpeg";
        fileSize = fileBuffer.length; // Update size after compression
      }
    } else if (imageUrl) {
      const response = await fetch(imageUrl);
      if (!response.ok) {
        throw new Error(
          `Failed to fetch image from URL: ${response.statusText}`
        );
      }
      fileBuffer = Buffer.from(await response.arrayBuffer());
      fileBuffer = await sharp(fileBuffer).jpeg({ quality: 80 }).toBuffer();
      finalFileName = `image-${uuidv4()}.jpeg`;
      contentType = "image/jpeg";
      fileSize = fileBuffer.length;
    } else {
      throw new Error("Either file or imageUrl must be provided.");
    }

    const filePath = `${uploadPath}/${finalFileName}`;

    // Create the PutObjectCommand
    const putCommand = new PutObjectCommand({
      Bucket: process.env.STORAGE_BUCKET,
      Key: filePath,
      Body: fileBuffer,
      ContentType: contentType,
    });

    // Add custom headers to fix checksum issue
    const headers: Record<string, string> = {
      "x-amz-checksum-algorithm": '"CRC32"',
    };

    putCommand.middlewareStack.add(
      (next) =>
        async (args): Promise<any> => {
          const request = args.request as any;

          if (!request.headers) {
            request.headers = {};
          }

          Object.entries(headers).forEach(([key, value]) => {
            request.headers[key] = value;
          });

          return next(args);
        },
      { step: "build", name: "customHeaders" }
    );

    await s3.send(putCommand);

    const publicUrl = `${process.env.STORAGE_PUBLIC_URL}/${filePath}`;

    // Only store metadata if not skipped and userId is provided
    if (!skipMetadata && userId) {
      const { error } = await supabase.from("file_uploads").insert({
        user_id: userId,
        chat_id: chatId,
        context: `${uploadPath}:${contentType}`,
        filename: finalFileName,
        original_name: originalName,
        content_type: contentType,
        size: fileSize,
        url: publicUrl,
        metadata: {
          uploadPath,
          contentType,
          originalContentType: file?.type || contentType,
        },
      });

      if (error) {
        console.error("Error storing file metadata in Supabase:", error);
        throw error;
      }
    }

    return {
      url: publicUrl,
      path: filePath,
      filename: finalFileName,
      originalName,
      contentType,
      size: fileSize,
    };
  } catch (error) {
    console.error("Error in file upload:", error);
    throw error;
  }
}

