// useFormData.ts
import { useState } from "react";
import { FormFields } from "@/lib/types/toolconfig";

export const useFormData = (initialFields: FormFields[]) => {
  const initialState = initialFields.reduce(
    (acc: { [key: string]: string }, field: FormFields) => {
      acc[field.name!] = field.initialValue || ""; // Provide a default empty string if initialValue is undefined
      return acc;
    },
    {}
  );

  const [formData, setFormData] = useState<{ [key: string]: string }>(
    initialState
  );

  const handleChange = (
    e: React.ChangeEvent<
      HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement
    >,
    fieldName: string
  ) => {
    setFormData((prevState) => ({ ...prevState, [fieldName]: e.target.value }));
  };

  return [formData, handleChange] as const;
};

lib/middleware/authMiddleware.ts.content:
import { NextRequest, NextResponse } from "next/server";
import { createClient } from "@/lib/utils/supabase/server";

export async function authMiddleware(req: NextRequest) {
  // Create a Supabase client for server-side operations
  const supabase = await createClient();

  // Attempt to get the current user from the session
  const {
    data: { user },
  } = await supabase.auth.getUser();

  // If no user is found, return a 401 Unauthorized response
  if (!user) {
    return NextResponse.json(
      { error: "User not authenticated" },
      { status: 401 }
    );
  }

  // Attach the user object to the request for use in subsequent middleware or route handlers
  // Note: TypeScript doesn't know about this custom property, so we use type assertion
  (req as any).user = user;

  // Allow the request to proceed to the next middleware or route handler
  return NextResponse.next();
}

