"use client";

import { Share2, Twitter, Linkedin } from "lucide-react";
import { FaWhatsapp } from "react-icons/fa";
import { Button } from "@/components/ui/button";

// Sharing utility
function getShareUrl(
  type: "twitter" | "linkedin" | "whatsapp",
  text: string,
  url: string
) {
  const encodedText = encodeURIComponent(text);
  const encodedUrl = encodeURIComponent(url);

  switch (type) {
    case "twitter":
      return `https://x.com/intent/tweet?text=${encodedText}&url=${encodedUrl}`;
    case "linkedin":
      return `https://www.linkedin.com/sharing/share-offsite/?url=${encodedUrl}`;
    case "whatsapp":
      return `https://wa.me/?text=${encodedText}%20${encodedUrl}`;
  }
}

interface ShareButtonsProps {
  text: string;
  path: string;
  marginTop?: string;
  showShareText?: boolean;
}

export default function ShareButtons({
  text,
  path,
  marginTop = "mt-4",
  showShareText = true,
}: ShareButtonsProps) {
  const fullUrl = `https://anotherwrapper.com${path}`;

  return (
    <div
      className={`flex items-center gap-2 ${marginTop} pt-4 border-t border-gray-100`}
    >
      {showShareText && (
        <span className="text-sm text-gray-500 flex items-center gap-1">
          <Share2 className="w-4 h-4" /> Share:
        </span>
      )}
      <Button
        variant="ghost"
        size="sm"
        className="text-blue-400 hover:bg-blue-50 hover:text-blue-500"
        onClick={() =>
          window.open(getShareUrl("twitter", text, fullUrl), "_blank")
        }
      >
        <Twitter className="w-4 h-4" />
      </Button>
      <Button
        variant="ghost"
        size="sm"
        className="text-blue-600 hover:bg-blue-50 hover:text-blue-700"
        onClick={() =>
          window.open(getShareUrl("linkedin", text, fullUrl), "_blank")
        }
      >
        <Linkedin className="w-4 h-4" />
      </Button>
      <Button
        variant="ghost"
        size="sm"
        className="text-green-500 hover:bg-green-50 hover:text-green-600"
        onClick={() =>
          window.open(getShareUrl("whatsapp", text, fullUrl), "_blank")
        }
      >
        <FaWhatsapp className="w-4 h-4" />
      </Button>
    </div>
  );
}

components/(apps)/dashboard/sidebar.tsx.content:
"use client";

import Image from "next/image";
import Link from "next/link";
import { usePathname } from "next/navigation";
import React, { useState, useCallback } from "react";
import { User } from "@supabase/supabase-js";
import { twMerge } from "tailwind-merge";
import {
  IconLayoutSidebarRightCollapse,
  IconChevronRight,
} from "@tabler/icons-react";
import { isMobile } from "@/lib/utils";
import { SidebarHistory } from "@/app/(apps)/chat/components/sidebar/sidebar-history";
import { Badge } from "@/components/(apps)/dashboard/badge";
import { Heading } from "./heading";
import { IconLogout, IconLogin } from "@tabler/icons-react";

// Import navlinks from config
import {
  navlinks,
  freeTools,
  landingPages,
  otherLinks,
  overviewLinks,
} from "./links";

interface UnifiedSidebarProps {
  user: User | null;
  showChatHistory?: boolean;
}

const NewBadge = () => (
  <span className="ml-2 inline-flex items-center rounded-lg bg-sky-500/10 px-1.5 py-0.5 text-[10px] font-medium text-sky-500 ring-1 ring-inset ring-sky-500/20">
    New
  </span>
);
const UpdatedBadge = () => (
  <span className="ml-2 inline-flex items-center rounded-lg bg-green-500/10 px-1.5 py-0.5 text-[10px] font-medium text-green-500 ring-1 ring-inset ring-emerald-500/20">
    Updated
  </span>
);

const SidebarHeader = React.memo(() => (
  <Link className="px-2 mb-4" href="/">
    <Image
      src="/logo-text.png"
      alt="Logo"
      width={400}
      height={100}
      quality={100}
      className="w-full"
    />
  </Link>
));

SidebarHeader.displayName = "SidebarHeader";

export function UnifiedSidebar({
  user,
  showChatHistory = false,
}: UnifiedSidebarProps) {
  const [open, setOpen] = useState(!isMobile());
  const [isChatExpanded, setIsChatExpanded] = useState(true);
  const [showAllHistory, setShowAllHistory] = useState(false);
  const pathname = usePathname();

  const isActive = useCallback((href: string) => pathname === href, [pathname]);

  // Separate chat link from other navlinks
  const chatLink = navlinks.find((link) => link.label === "Chat AI");
  const otherNavlinks = navlinks.filter((link) => link.label !== "Chat AI");

  const renderLinks = useCallback(
    (links: any[], heading: string, defaultExternal: boolean = false) => {
      // Add logout/login link to otherLinks when rendering that section
      const linksToRender =
        heading === "Other"
          ? [
              ...links,
              user
                ? {
                    href: "/api/auth/signout",
                    label: "Logout",
                    icon: IconLogout,
                  }
                : { href: "/auth", label: "Login", icon: IconLogin },
            ]
          : links;

      return (
        <>
          <Heading
            as="p"
            className="text-sm md:text-sm lg:text-sm px-2 pt-2 mb-2"
          >
            {heading}
          </Heading>

          {/* Always render Chat AI first in Demo Apps section */}
          {heading === "Demo Apps" && chatLink && (
            <>
              {showChatHistory ? (
                <div className="mb-1">
                  <button
                    onClick={() => setIsChatExpanded(!isChatExpanded)}
                    className={twMerge(
                      "w-full text-primary hover:text-primary/50 transition duration-200 flex items-center justify-between py-2 px-4 rounded-md text-sm",
                      pathname.includes("/chat") &&
                        "bg-white shadow-lg text-primary"
                    )}
                  >
                    <div className="flex items-center space-x-2">
                      <chatLink.icon
                        className={twMerge(
                          "h-4 w-4 flex-shrink-0",
                          pathname.includes("/chat") && "text-sky-500"
                        )}
                      />
                      <span>{chatLink.label}</span>
                      {chatLink.isNew && <NewBadge />}
                    </div>
                    <IconChevronRight
                      className={`h-4 w-4 transition-transform duration-200 ${
                        isChatExpanded ? "rotate-90" : ""
                      }`}
                    />
                  </button>

                  {isChatExpanded && (
                    <div className="ml-4">
                      <SidebarHistory
                        user={user ?? undefined}
                        limit={3}
                        showAllHistory={showAllHistory}
                        setShowAllHistory={setShowAllHistory}
                      />
                    </div>
                  )}
                </div>
              ) : (
                <Link
                  href={chatLink.href}
                  prefetch={!chatLink.isExternal}
                  target={chatLink.isExternal ? "_blank" : undefined}
                  rel={chatLink.isExternal ? "noopener noreferrer" : undefined}
                  onClick={() => isMobile() && setOpen(false)}
                  className={twMerge(
                    "text-primary hover:text-primary/50 transition duration-200 flex items-center space-x-2 py-2 px-4 rounded-md text-sm",
                    isActive(chatLink.href) && "bg-white shadow-lg text-primary"
                  )}
                >
                  <chatLink.icon
                    className={twMerge(
                      "h-4 w-4 flex-shrink-0",
                      isActive(chatLink.href) && "text-sky-500"
                    )}
                  />
                  <span>{chatLink.label}</span>
                  {chatLink.isNew && <NewBadge />}
                </Link>
              )}
            </>
          )}

          {/* Render other links */}
          {linksToRender.map((link) => {
            if (heading === "Demo Apps" && link.label === "Chat AI")
              return null;
            const isExternal = link.isExternal ?? defaultExternal;

            return (
              <Link
                key={link.href}
                href={link.href}
                prefetch={!isExternal}
                target={isExternal ? "_blank" : undefined}
                rel={isExternal ? "noopener noreferrer" : undefined}
                onClick={(e) => {
                  if (link.label === "Logout") {
                    e.preventDefault();
                    fetch(link.href, { method: "POST" }).then(() => {
                      window.location.href = "/auth";
                    });
                  } else if (isMobile()) {
                    setOpen(false);
                  }
                }}
                className={twMerge(
                  "text-primary hover:text-primary/50 transition duration-200 flex items-center space-x-2 py-2 px-4 rounded-md text-sm",
                  isActive(link.href) && "bg-white shadow-lg text-primary"
                )}
              >
                <link.icon
                  className={twMerge(
                    "h-4 w-4 flex-shrink-0",
                    isActive(link.href) && "text-sky-500"
                  )}
                />
                <span>{link.label}</span>
                {link.isNew && <NewBadge />}
                {link.isUpdated && <UpdatedBadge />}
              </Link>
            );
          })}
        </>
      );
    },
    [
      isActive,
      isChatExpanded,
      pathname,
      user,
      showChatHistory,
      showAllHistory,
      setShowAllHistory,
    ]
  );

  const handleBadgeClick = () => {
    if (isMobile()) {
      setOpen(false);
    }
  };

  return (
    <>
      <div className={`lg:block ${open ? "block" : "hidden"}`}>
        <div className="px-3 z-40 pb-4 bg-neutral-100 w-[220px] fixed lg:relative h-screen left-0 flex flex-col justify-between">
          <div className="flex-1 overflow-auto no-scrollbar">
            <SidebarHeader />

            <div className="flex flex-col space-y-1 relative z-40">
              <div className="flex flex-col">
                {renderLinks(overviewLinks, "Overview")}
                {renderLinks(navlinks, "Demo Apps")}
                {renderLinks(freeTools, "Free Tools", true)}
                {renderLinks(otherLinks, "Other", true)}
                {renderLinks(landingPages, "Landing Pages", true)}
              </div>
            </div>
          </div>

          <div className="pb-4">
            <div onClick={handleBadgeClick}>
              <Badge
                href="https://anotherwrapper.lemonsqueezy.com/buy/c1a15bd7-58b0-4174-8d1a-9bca6d8cb511"
                text="Build your startup"
                icon={IconChevronRight}
                className="w-full"
              />
            </div>
          </div>
        </div>
      </div>

      <button
        className="fixed lg:hidden bottom-4 right-4 h-8 w-8 border border-neutral-200 rounded-full backdrop-blur-sm flex items-center justify-center z-40"
        onClick={() => setOpen(!open)}
      >
        <IconLayoutSidebarRightCollapse className="h-4 w-4 text-primary" />
      </button>
    </>
  );
}

components/(apps)/dashboard/text-generat.content:
"use client";

import * as React from "react";
import {
  ColumnDef,
  flexRender,
  getCoreRowModel,
  useReactTable,
  getPaginationRowModel,
  SortingState,
  getSortedRowModel,
} from "@tanstack/react-table";
import { ArrowUpDown, Calendar, Bot } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { useRouter } from "next/navigation";
import { useDebounce } from "@/lib/hooks/useDebounce";
import { format } from "date-fns";

interface Generation {
  id: string;
  slug: string;
  created_at: string;
  model: string;
  type: string;
  title: string | null;
  subtitle: string | null;
  description: string | null;
}

interface UserGenerationsProps {
  generations: Generation[];
  generationType: "llama" | "gpt" | "vision" | "claude" | "grok";
}

export function UserGenerations({
  generations,
  generationType,
}: UserGenerationsProps) {
  const router = useRouter();
  const [sorting, setSorting] = React.useState<SortingState>([]);
  const [filterValue, setFilterValue] = React.useState("");
  const debouncedFilterValue = useDebounce(filterValue, 300);

  const columns: ColumnDef<Generation>[] = React.useMemo(
    () => [
      {
        accessorKey: "title",
        header: ({ column }) => {
          return (
            <Button
              variant="ghost"
              onClick={() =>
                column.toggleSorting(column.getIsSorted() === "asc")
              }
            >
              Title
              <ArrowUpDown className="ml-2 h-4 w-4" />
            </Button>
          );
        },
        cell: ({ row }) => (
          <div className="font-medium">
            {row.getValue("title") || "Untitled"}
          </div>
        ),
      },
      {
        accessorKey: "subtitle",
        header: "Subtitle",
        cell: ({ row }) => (
          <div className="text-sm text-muted-foreground">
            {row.getValue("subtitle") || "No subtitle"}
          </div>
        ),
      },
      {
        accessorKey: "created_at",
        header: "Date",
        cell: ({ row }) => (
          <div className="flex items-center">
            <Calendar className="mr-2 h-4 w-4 text-muted-foreground" />
            <span className="text-sm">
              {format(new Date(row.getValue("created_at")), "dd/MM/yyyy")}
            </span>
          </div>
        ),
      },
      {
        accessorKey: "model",
        header: "Model",
        cell: ({ row }) => (
          <div className="flex items-center whitespace-nowrap">
            <Bot className="mr-2 h-4 w-4 text-muted-foreground flex-shrink-0" />
            <Badge className="bg-black text-white hover:bg-black/80 text-xs">
              {row.getValue("model")}
            </Badge>
          </div>
        ),
      },
    ],
    []
  );

  const filteredGenerations = React.useMemo(() => {
    return generations.filter(
      (gen) =>
        gen.title?.toLowerCase().includes(debouncedFilterValue.toLowerCase()) ||
        gen.subtitle
          ?.toLowerCase()
          .includes(debouncedFilterValue.toLowerCase()) ||
        gen.model.toLowerCase().includes(debouncedFilterValue.toLowerCase())
    );
  }, [generations, debouncedFilterValue]);

  const table = useReactTable({
    data: filteredGenerations,
    columns,
    getCoreRowModel: getCoreRowModel(),
    getPaginationRowModel: getPaginationRowModel(),
    onSortingChange: setSorting,
    getSortedRowModel: getSortedRowModel(),
    state: {
      sorting,
    },
  });

  const { rows } = table.getRowModel();
  const [visibleRange, setVisibleRange] = React.useState({ start: 0, end: 20 });

  const observerRef = React.useRef<IntersectionObserver | null>(null);
  const lastRowRef = React.useRef<HTMLTableRowElement | null>(null);

  React.useEffect(() => {
    observerRef.current = new IntersectionObserver(
      (entries) => {
        if (entries[0].isIntersecting) {
          setVisibleRange((prev) => ({
            start: prev.start,
            end: Math.min(prev.end + 20, rows.length),
          }));
        }
      },
      { threshold: 0.1 }
    );

    return () => observerRef.current?.disconnect();
  }, [rows.length]);

  React.useEffect(() => {
    if (lastRowRef.current && observerRef.current) {
      observerRef.current.observe(lastRowRef.current);
    }
    return () => {
      if (lastRowRef.current && observerRef.current) {
        observerRef.current.unobserve(lastRowRef.current);
      }
    };
  }, [visibleRange]);

  React.useEffect(() => {
    setVisibleRange({ start: 0, end: 20 }); // Reset visible range when filter changes
  }, [debouncedFilterValue]);

  const handleFilterChange = React.useCallback(
    (event: React.ChangeEvent<HTMLInputElement>) => {
      setFilterValue(event.target.value);
    },
    []
  );

  return (
    <div className="space-y-4">
      <h2 className="text-3xl font-bold">Your Generations</h2>
      <div className="flex items-center py-4">
        <Input
          placeholder="Filter generations..."
          value={filterValue}
          onChange={handleFilterChange}
          className="max-w-sm"
        />
      </div>
      <div className="rounded-md border">
        <Table>
          <TableHeader>
            {table.getHeaderGroups().map((headerGroup) => (
              <TableRow key={headerGroup.id}>
                {headerGroup.headers.map((header) => (
                  <TableHead key={header.id}>
                    {header.isPlaceholder
                      ? null
                      : flexRender(
                          header.column.columnDef.header,
                          header.getContext()
                        )}
                  </TableHead>
                ))}
              </TableRow>
            ))}
          </TableHeader>
          <TableBody>
            {rows.length === 0 ? (
              <TableRow>
                <TableCell
                  colSpan={columns.length}
                  className="h-24 text-center"
                >
                  No results found.
                </TableCell>
              </TableRow>
            ) : (
              rows
                .slice(visibleRange.start, visibleRange.end)
                .map((row, index) => (
                  <TableRow
                    key={row.id}
                    ref={
                      index === visibleRange.end - visibleRange.start - 1
                        ? lastRowRef
                        : null
                    }
                    data-state={row.getIsSelected() && "selected"}
                    className="cursor-pointer hover:bg-muted/50"
                    onClick={() =>
                      router.push(
                        `/apps/${generationType}/${row.original.slug}`
                      )
                    }
                  >
                    {row.getVisibleCells().map((cell) => (
                      <TableCell key={cell.id}>
                        {flexRender(
                          cell.column.columnDef.cell,
                          cell.getContext()
                        )}
                      </TableCell>
                    ))}
                  </TableRow>
                ))
            )}
          </TableBody>
        </Table>
      </div>
      <div className="flex items-center justify-end space-x-2 py-4">
        <Button
          variant="outline"
          size="sm"
          onClick={() => table.previousPage()}
          disabled={!table.getCanPreviousPage()}
        >
          Previous
        </Button>
        <Button
          variant="outline"
          size="sm"
          onClick={() => table.nextPage()}
          disabled={!table.getCanNextPage()}
        >
          Next
        </Button>
