import React from "react";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import {
  Select,
  SelectTrigger,
  SelectContent,
  SelectItem,
  SelectValue,
  SelectGroup,
} from "@/components/ui/select";
import { Label } from "@/components/ui/label";
import { type FormFields } from "@/lib/types/toolconfig";

interface RenderFieldsProps {
  fields: FormFields[];
  formData: { [key: string]: string };
  handleChange: (
    event: React.ChangeEvent<
      HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement
    >,
    fieldName: string
  ) => void;
}

export const RenderFields: React.FC<RenderFieldsProps> = ({
  fields,
  formData,
  handleChange,
}) => {
  return (
    <div className="space-y-8">
      {fields.map((field) => (
        <div key={field.name} className="relative">
          <Label
            htmlFor={field.name}
            className="text-sm text-gray-600 font-medium mb-2 block"
          >
            {field.label}
            {field.required && <span className="text-primary ml-1">*</span>}
          </Label>

          {field.type === "input" && (
            <Input
              value={formData[field.name!]}
              onChange={(e) => handleChange(e, field.name!)}
              type="text"
              required={field.required}
              placeholder={field.placeholder || "Enter text"}
              id={field.name}
              name={field.name}
              className="w-full bg-gray-50/50 border border-gray-100 rounded-lg px-4 py-3 
                placeholder:text-gray-400 text-gray-900 focus:ring-2 focus:ring-primary/10 
                focus:border-primary/30 transition-all duration-200"
            />
          )}

          {field.type === "textarea" && (
            <Textarea
              value={formData[field.name!]}
              onChange={(e) => handleChange(e, field.name!)}
              required={field.required}
              placeholder={field.placeholder || "Enter text"}
              id={field.name}
              name={field.name}
              className="w-full min-h-[120px] bg-gray-50/50 border border-gray-100 rounded-lg 
                px-4 py-3 placeholder:text-gray-400 text-gray-900 focus:ring-2 
                focus:ring-primary/10 focus:border-primary/30 transition-all duration-200"
            />
          )}

          {field.type === "select" && (
            <Select
              value={formData[field.name!]}
              onValueChange={(value) =>
                handleChange(
                  {
                    target: { value } as any,
                  } as React.ChangeEvent<HTMLSelectElement>,
                  field.name!
                )
              }
            >
              <SelectTrigger
                className="w-full bg-gray-50/50 border border-gray-100 rounded-lg px-4 py-3 
                  text-gray-900 focus:ring-2 focus:ring-primary/10 focus:border-primary/30 
                  transition-all duration-200"
              >
                <SelectValue placeholder="Select an option" />
              </SelectTrigger>
              <SelectContent className="border-gray-100 rounded-xl overflow-hidden">
                <SelectGroup>
                  {field.options?.map((option) => (
                    <SelectItem
                      key={option}
                      value={option}
                      className="hover:bg-gray-50 focus:bg-gray-50 hover:text-gray-900 focus:text-gray-900 px-4 py-2.5 cursor-pointer"
                    >
                      {option}
                    </SelectItem>
                  ))}
                </SelectGroup>
              </SelectContent>
            </Select>
          )}
        </div>
      ))}
    </div>
  );
};

components/(apps)/input/image-upload.tsx.content:
"use client";

import React, { useState } from "react";
import { FileUpload } from "@/components/ui/image-upload";
import { Button } from "@/components/ui/button";
import { X, Loader2 } from "lucide-react";

const ImageUpload: React.FC<any> = ({
  currentImg = null,
  uploadConfig,
  setImageUrl,
}) => {
  const [uploading, setUploading] = useState<boolean>(false);
  const [src, setSrc] = useState<string | null>(currentImg);

  const handleFileUpload = async (files: File[]) => {
    if (files.length === 0) {
      alert("You must select an image to upload.");
      return;
    }

    const file = files[0];

    if (!file.type.startsWith("image/")) {
      alert("Please select a valid image file.");
      return;
    }

    try {
      setUploading(true);

      let formData = new FormData();
      formData.append("image", file);
      formData.append("uploadPath", uploadConfig.path);

      const response = await fetch("/vision/api/upload", {
        method: "POST",
        body: formData,
      });

      if (!response.ok) {
        throw new Error(`Failed to upload image: ${response.statusText}`);
      }

      const data = await response.json();
      console.log("Upload response:", data);
      setSrc(data.url);
      setImageUrl(data.url);
    } catch (error) {
      console.error("Upload error:", error);
      alert((error as Error).message);
    } finally {
      setUploading(false);
    }
  };

  const removeImage = () => {
    setSrc(null);
    setImageUrl(null);
  };

  return (
    <div className="mb-4 w-full max-w-4xl mx-auto min-h-96 border border-dashed bg-white dark:bg-black border-neutral-200 dark:border-neutral-800 rounded-lg relative overflow-hidden">
      {src ? (
        <div className="relative">
          <img
            src={src}
            alt="Uploaded"
            className="w-full h-full object-cover"
          />
          <button
            onClick={removeImage}
            className="absolute top-2 right-2 p-1 bg-black bg-opacity-50 rounded-full text-white hover:bg-opacity-70 transition-opacity"
            aria-label="Remove image"
          >
            <X className="h-4 w-4" />
          </button>
        </div>
      ) : (
        <FileUpload onChange={handleFileUpload} />
      )}
      {uploading && (
        <div className="absolute inset-0 bg-black bg-opacity-50 flex items-center justify-center">
          <Loader2 className="h-8 w-8 text-white animate-spin" />
        </div>
      )}
    </div>
  );
};

export default ImageUpload;

