                { icon: Clock, top: "50%", left: "10%" },
                { icon: Lock, top: "70%", left: "20%" },
                { icon: KeyRound, top: "90%", left: "50%" },
                { icon: Clock, top: "70%", left: "80%" },
                { icon: Lock, top: "50%", left: "90%" },
                { icon: KeyRound, top: "30%", left: "80%" },
