"use client";

import { useState } from "react";

interface GoogleSignInButtonProps {
  next?: string;
}

export default function GoogleSignInButton({ next }: GoogleSignInButtonProps) {
  const [isLoading, setIsLoading] = useState(false);

  const signInWithGoogle = async () => {
    setIsLoading(true);

    try {
      const response = await fetch("/api/auth/google", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ next }),
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.message);
      }

      if (data.url) {
        window.location.href = data.url;
      } else {
        throw new Error("No URL returned from the server");
      }
    } catch (error) {
      console.error("Error initiating Google Sign-In:", error);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="w-full">
      <button
        onClick={signInWithGoogle}
        disabled={isLoading}
        className="rounded-xl w-full h-30 flex flex-shrink-0 content-center items-center justify-center border border-base-200 bg-white px-6 py-3 text-center font-medium text-black shadow-sm hover:bg-gray-50 hover:border-gray-300 focus:outline-none focus:ring-1 focus:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed"
