              </li>
            ))}
            {user && (
              <li className="text-base-content">
                <SignOutButton />
              </li>
            )}
          </ul>
        </div>
        <a className="flex text-xl" href={companyConfig.homeUrl}>
          {" "}
          <img src={companyConfig.logo} alt="Logo" className="h-8 w-8" />
