          className={`text-${navbarConfig.textColor} menu menu-horizontal px-1`}
        >
          {companyConfig.navbarLinks.map((link, index) => (
            <li key={index}>
              <Link href={link.href}>{link.label}</Link>
            </li>
          ))}
