import { UIMessage } from "ai";
import { useCopyToClipboard } from "usehooks-ts";
import { useState } from "react";
import { CopyIcon, CheckIcon } from "lucide-react";
import { Button } from "@/components/ui/button";

export function MessageActions({
  message,
  isLoading,
}: {
  message: UIMessage;
  isLoading: boolean;
}) {
  const [_, copyToClipboard] = useCopyToClipboard();
  const [hasCopied, setHasCopied] = useState(false);

  if (isLoading) return null;
  if (message.role === "user") return null;
  // Check if message has tool-related parts (V5)
  const hasToolParts = message.parts?.some(
    (part: any) => part.type?.startsWith('tool-') || part.type === 'dynamic-tool'
  );
  if (hasToolParts) return null;

  const handleCopy = async () => {
    // Extract text from parts for v5 compatibility
    const textContent = message.parts
      ?.filter((part) => part.type === "text")
      .map((part) => (part as any).text)
      .join("")
      || "";
    await copyToClipboard(textContent);
    setHasCopied(true);
    setTimeout(() => setHasCopied(false), 2000); // Reset after 2 seconds
  };

  return (
    <div className="flex flex-row gap-2">
      <Button
        className="py-1 px-2 text-xs h-fit hover:bg-primary/10 text-primary hover:text-primary"
        variant="ghost"
        onClick={handleCopy}
      >
        {hasCopied ? (
          <CheckIcon className="text-xs text-green-500 w-4 h-4" />
        ) : (
          <CopyIcon className="text-xs w-4 h-4" />
        )}
      </Button>
    </div>
  );
}

app/(apps)/chat/components/message.tsx.content:
"use client";

import {
  UIMessage,
  TextUIPart,
  FileUIPart,
  ToolUIPart,
  DynamicToolUIPart,
} from "ai";
import { extractSearchResults } from "./search-result-handler";
import cx from "classnames";
import { motion } from "framer-motion";
import { Dispatch, SetStateAction, useState } from "react";
import {
  BrainCircuitIcon,
  ChevronDown,
  ChevronUp,
  Globe,
  ComputerIcon,
} from "lucide-react";
import { UIBlock } from "./canvas/canvas";
import {
  DocumentToolCall,
  DocumentToolResult,
  AppSuggestionToolCall,
} from "./agent-actions";
import { Markdown } from "./markdown";
import { MessageActions } from "./message-actions";
import { PreviewAttachment } from "./preview-attachment";
import { Button } from "@/components/ui/button";
import { AppCards } from "./widgets/app-cards";
import { cn } from "@/lib/utils";

// V5 tool states
type ToolState =
  | "input-streaming"
  | "input-available"
  | "output-available"
  | "output-error";

interface ToolStatus {
  content: string;
  progress?: {
    found: number;
    scraped: number;
  };
}

interface InternetSearchResultProps {
  result?: {
    sources?: Array<{ title: string; url: string }>;
    summary?: string;
    // Native provider formats
    webSearchQueries?: string[]; // Google
    searchEntryPoint?: any; // Google
    groundingSupports?: any[]; // Google
    citations?: any[]; // OpenAI/Anthropic
  };
  isLoading: boolean;
  status?: string;
  toolName?: string;
  state?: ToolState;
}

interface ExtendedMessage extends UIMessage {
  // No additional properties needed - UIMessage now has parts array
}

interface PreviewMessageProps {
  message: ExtendedMessage;
  block: UIBlock;
  setBlock: Dispatch<SetStateAction<UIBlock>>;
  isLoading?: boolean;
  className?: string;
}

export function PreviewMessage({
  message,
  block,
  setBlock,
  isLoading,
  className,
}: PreviewMessageProps) {
  return (
    <motion.div
      className="w-full mx-auto max-w-3xl px-4 group/message"
      initial={{ y: 5, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      data-role={message.role}
    >
      <div
        className={cx(
          "flex gap-4 rounded-2xl",
          {
            "bg-base-100 text-primary px-4 py-3 w-fit ml-auto max-w-2xl":
              message.role === "user",
            "w-full": message.role === "assistant",
          },
          className
        )}
      >
        {message.role === "assistant" && (
          <div className="flex items-start pt-1">
            <div className="size-8 flex items-center rounded-full justify-center shrink-0">
              <BrainCircuitIcon
                size={14}
                className="text-muted-foreground/70"
              />
            </div>
          </div>
        )}

        <div className="flex flex-col gap-3 w-full">
          {message.parts?.some((part) => part.type === "file") && (
            <div className="flex flex-wrap gap-1">
              {message.parts
                ?.filter((part) => part.type === "file")
                .map((part, index) => {
                  const filePart = part as FileUIPart;
                  return (
                    <div key={filePart.url || index} className="flex-shrink-0">
                      <PreviewAttachment
                        attachment={{
                          url: filePart.url,
                          contentType: filePart.mediaType || "",
                          name: filePart.url?.split("/").pop() || "file",
                        }}
                        showFileName={false}
                        size="normal"
                      />
                    </div>
                  );
                })}
            </div>
          )}

          {/* Render all parts in order */}
          <div className="flex flex-col gap-4">
            {message.parts?.map((part, index) => {
              // Skip step-start parts entirely to avoid showing false "Processed" messages
              if (part.type === "step-start") {
                return null;
              }

              // Handle text parts
              if (part.type === "text") {
                const textPart = part as TextUIPart;
                return textPart.text?.trim() ? (
                  <div
                    key={`text-${index}`}
                    className="prose dark:prose-invert group-data-[role=user]/message:text-primary"
                  >
                    <Markdown>{textPart.text}</Markdown>
                  </div>
                ) : null;
              }

              // Handle tool parts
              if (
                part.type &&
                (part.type.startsWith("tool-") || part.type === "dynamic-tool")
              ) {
                const toolPart = part as ToolUIPart<any> | DynamicToolUIPart;
                const toolName =
                  toolPart.type === "dynamic-tool"
                    ? toolPart.toolName
                    : toolPart.type.replace("tool-", "");
                const state: ToolState = toolPart.state || "input-available";
                const output =
                  toolPart.state === "output-available"
                    ? toolPart.output
                    : undefined;
                const status =
                  "status" in toolPart &&
                  toolPart.status &&
                  typeof toolPart.status === "object" &&
                  "content" in toolPart.status
                    ? (toolPart.status as ToolStatus)
                    : undefined;

                // For web search tools, always render the component and let it handle states internally
                if (
                  toolName === "web_search" ||
                  toolName === "google_search" ||
                  toolName === "web_search_preview"
                ) {
                  // Determine loading state based on tool state
                  const isLoading =
                    state !== "output-available" && state !== "output-error";

                  // Get status text based on state
                  let statusText = status?.content;
                  if (!statusText) {
                    switch (state) {
                      case "input-streaming":
                        statusText = "Preparing web search...";
                        break;
                      case "input-available":
                        statusText = "Searching the web...";
                        break;
                      case "output-error":
                        statusText = "Search failed";
                        break;
                      default:
                        statusText = "Searching the web...";
                    }
                  }

                  return (
                    <div key={`tool-${index}`}>
                      <InternetSearchResult
                        isLoading={isLoading}
                        result={output as InternetSearchResultProps["result"]}
                        status={statusText}
                        toolName={toolName}
                        state={state}
                      />
                    </div>
                  );
                }

                // Handle other tools
                if (state === "output-available") {
                  return (
                    <div key={`tool-${index}`}>
                      {toolName === "createDocument" ? (
                        <DocumentToolResult
                          type="create"
                          result={output}
                          block={block}
                          setBlock={setBlock}
                        />
                      ) : toolName === "updateDocument" ? (
                        <DocumentToolResult
                          type="update"
                          result={output}
                          block={block}
                          setBlock={setBlock}
                        />
                      ) : toolName === "suggestApps" ? (
                        <AppSuggestionResult
                          isLoading={false}
                          result={output as AppSuggestionResultProps["result"]}
                          status={status?.content}
                        />
                      ) : (
                        <pre>{JSON.stringify(output, null, 2)}</pre>
                      )}
                    </div>
                  );
                } else {
                  // Tool is still processing
                  return (
                    <div
                      key={`tool-${index}`}
                      className={cx({ skeleton: false })}
                    >
                      <div className="flex items-center">
                        {toolName === "createDocument" ? (
                          <DocumentToolCall
                            type="create"
                            args={toolPart.input}
                          />
                        ) : toolName === "updateDocument" ? (
                          <DocumentToolCall
                            type="update"
                            args={toolPart.input}
                          />
                        ) : toolName === "suggestApps" ? (
                          <AppSuggestionToolCall args={toolPart.input} />
                        ) : null}
                      </div>
                    </div>
                  );
                }
              }

              return null;
            })}
          </div>

          <MessageActions message={message} isLoading={isLoading || false} />
        </div>
      </div>
    </motion.div>
  );
}

export const ThinkingMessage = () => {
  const role = "assistant";

  return (
    <motion.div
      className="w-full mx-auto max-w-3xl px-4 group/message"
      initial={{ y: 5, opacity: 0 }}
      animate={{ y: 0, opacity: 1, transition: { delay: 1 } }}
      data-role={role}
    >
      <div
        className={cx(
          "flex gap-4 items-center w-full group-data-[role=user]/message:px-3 w-full group-data-[role=user]/message:w-fit group-data-[role=user]/message:ml-auto group-data-[role=user]/message:max-w-2xl group-data-[role=user]/message:py-2 rounded-xl",
          {
            "group-data-[role=user]/message:bg-muted": true,
          }
        )}
      >
        <div className="size-8 flex items-center rounded-full justify-center shrink-0">
          <BrainCircuitIcon size={14} className="text-muted-foreground/70" />
        </div>

        <div className="flex flex-col gap-2 w-full">
          <div className="flex flex-col gap-4 text-muted-foreground">
            Thinking...
          </div>
        </div>
      </div>
    </motion.div>
  );
};

const InternetSearchResult = ({
  result,
  isLoading,
  status,
  toolName,
  state,
}: InternetSearchResultProps) => {
  const [isOpen, setIsOpen] = useState(false);

  // Always show the search component once it appears
  // This prevents flickering by keeping it mounted
  if (isLoading || !result) {
    return (
      <div className="w-fit bg-background/50 border-[0.5px] border-border/40 py-2.5 px-3.5 rounded-lg flex flex-row items-center gap-3 shadow-[0_1px_3px_0_rgb(0,0,0,0.02)] backdrop-blur-[2px]">
        <div className="text-muted-foreground/70 flex items-center">
          <Globe className="h-[15px] w-[15px] animate-pulse" />
        </div>
        <div className="text-[13px] leading-[15px] text-muted-foreground/90">
          <span className="opacity-60 font-normal">
            {status || "Searching the web..."}
          </span>
        </div>
      </div>
    );
  }

  // Use the helper to extract search results in a unified format
  const searchResult = extractSearchResults(toolName || "web_search", result);
  if (!searchResult || searchResult.sources.length === 0) {
    // Show processed state even if no sources found
    return (
      <div className="w-fit bg-background/50 border-[0.5px] border-border/40 py-2.5 px-3.5 rounded-lg flex flex-row items-center gap-3 shadow-[0_1px_3px_0_rgb(0,0,0,0.02)] backdrop-blur-[2px]">
        <div className="text-muted-foreground/70 flex items-center">
          <Globe className="h-[15px] w-[15px]" />
        </div>
        <div className="text-[13px] leading-[15px] text-muted-foreground/90">
          <span className="opacity-60 font-normal">Processed</span>
        </div>
      </div>
    );
  }

  const { sources, summary } = searchResult;

  return (
    <div className="flex flex-col gap-4">
      <div className="w-fit bg-background/50 border-[0.5px] border-border/40 rounded-lg shadow-[0_1px_3px_0_rgb(0,0,0,0.02)] backdrop-blur-[2px] overflow-hidden">
        <div className="py-2.5 px-3.5 flex items-center justify-between gap-3">
          <div className="flex items-center gap-3">
            <div className="text-muted-foreground/70 flex items-center">
              <Globe className="h-[15px] w-[15px]" />
            </div>
            <div className="text-[13px] leading-[15px] text-muted-foreground/90">
              <span className="opacity-90 font-medium">
                {sources.length} sources found
              </span>
            </div>
          </div>
          <Button
            variant="ghost"
            size="sm"
            onClick={(e) => {
              e.preventDefault();
              setIsOpen(!isOpen);
            }}
            className="h-7 w-7 p-0 hover:bg-muted/50"
          >
            {isOpen ? (
              <ChevronUp className="h-[15px] w-[15px] text-muted-foreground/70" />
            ) : (
              <ChevronDown className="h-[15px] w-[15px] text-muted-foreground/70" />
            )}
          </Button>
        </div>

        {isOpen && (
          <>
            {result.summary && (
              <div className="px-3.5 pb-3.5 prose dark:prose-invert max-w-none text-[13px] leading-relaxed text-muted-foreground/90">
                <Markdown>{result.summary}</Markdown>
              </div>
            )}

            <div className="border-t border-border/40 divide-y divide-border/40">
              {sources.map((source, i) => (
                <a
                  key={i}
                  href={source.url}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="flex items-center gap-3 px-3.5 py-2 hover:bg-muted/30 transition-colors"
                >
                  <div className="flex items-center justify-center h-5 w-5 bg-background/80 rounded-md ring-[0.5px] ring-border/40">
                    <img
                      src={`https://www.google.com/s2/favicons?domain=${source.url}&sz=32`}
                      alt=""
                      className="h-3.5 w-3.5"
                    />
                  </div>
                  <span className="flex-1 text-[13px] leading-[15px] text-muted-foreground/90 line-clamp-1">
                    {source.title}
                  </span>
                  <ChevronDown className="h-[15px] w-[15px] rotate-[-90deg] text-muted-foreground/50" />
                </a>
              ))}
            </div>
          </>
        )}
      </div>
    </div>
  );
};

interface AppSuggestionResultProps {
  result?: {
    apps: any[];
    total: number;
    metadata?: {
      analysis?: string;
      needsCombination?: boolean;
      recommendedWorkflow?: string;
    };
  };
  isLoading: boolean;
  status?: string;
}

const AppSuggestionResult = ({
  result,
  isLoading,
  status,
}: AppSuggestionResultProps) => {
  const [showDetails, setShowDetails] = useState(false);

  return (
    <div className="flex flex-col gap-3">
      <div className="w-fit bg-background/50 border-[0.5px] border-border/40 py-2.5 px-3.5 rounded-lg flex flex-row items-center gap-3 shadow-[0_1px_3px_0_rgb(0,0,0,0.02)] backdrop-blur-[2px]">
        <div className="text-muted-foreground/70 flex items-center">
          <ComputerIcon
            className={cn("h-[15px] w-[15px]", {
              "animate-pulse": isLoading,
            })}
          />
        </div>
        <div className="text-[13px] leading-[15px] text-muted-foreground/90">
          <span className="opacity-90 font-medium">
            {isLoading
              ? status || "Finding relevant demo apps..."
              : `Found ${result?.total || 0} demo apps`}
          </span>
        </div>
      </div>

      {result?.apps && result.apps.length > 0 && (
        <>
          <AppCards apps={result.apps} />
        </>
      )}
    </div>
  );
};

app/(apps)/chat/components/multimodal-in.content:
"use client";

import { ChatRequestOptions, UIMessage } from "ai";
import cx from "classnames";
import { motion } from "framer-motion";
import React, {
  useRef,
  useEffect,
  useState,
  useCallback,
  Dispatch,
  SetStateAction,
  ChangeEvent,
} from "react";
import { useToast } from "@/components/ui/use-toast";
import { useLocalStorage, useWindowSize } from "usehooks-ts";
import Image from "next/image";
import { useRouter } from "next/navigation";
import { sanitizeUIMessages } from "@/lib/ai/chat";
import {
  AI_MODEL_DISPLAY,
  availableModels,
  AIModelDisplayInfo,
} from "@/lib/ai/models";
import { getCookie, setCookie } from "@/lib/utils/cookies";
import { ImageIcon } from "lucide-react";
import { PreviewAttachment } from "./preview-attachment";
import { Button } from "@/components/ui/button";
import { ArrowUpIcon, StopIcon } from "./icons";
import { Globe, X } from "lucide-react";
import { cn } from "@/lib/utils";

const suggestedActions = [
  {
    title: "Build a Youtube Script Generator",
    label: "How can I build a Youtube Script Generator with AnotherWrapper?",
    action:
      "I want to build a Youtube Script Generator. Which demo app can I use? It should generate text scripts, the audio for each scene + thumbnails for the video.",
    icon: "📹",
  },
  {
    title: "Write an essay",
    label: "Write an essay about Tupac Shakur",
    action: "I want to write an essay about the life of Tupac Shakur.",
    icon: "✨",
  },
];

interface MultimodalInputProps<TMessage extends UIMessage = UIMessage> {
  chatId: string;
  input: string;
  setInput: (value: string) => void;
  isLoading: boolean;
  stop: () => void;
  attachments: Array<{ url: string; contentType?: string; name?: string; }>;
  setAttachments: Dispatch<SetStateAction<Array<{ url: string; contentType?: string; name?: string; }>>>;
  containsImages: boolean;
  messages: Array<TMessage>;
  setMessages: Dispatch<SetStateAction<Array<TMessage>>>;
  append: (
    message: TMessage | { role: 'user' | 'assistant'; content: string },
    chatRequestOptions?: ChatRequestOptions
  ) => Promise<string | null | undefined>;
  handleSubmit: (
    event?: {
      preventDefault?: () => void;
    },
    chatRequestOptions?: ChatRequestOptions & {
      selectedModelId?: string;
      isBrowseEnabled?: boolean;
    }
  ) => void;
  className?: string;
  selectedModelId: string;
  onModelChange?: (modelId: string) => void;
  onBrowseToggle?: (enabled: boolean) => void;
  isBrowseEnabled: boolean;
  isAuthenticated: boolean;
}

// Add an interface for upload queue items
interface UploadQueueItem {
  id: string;
  name: string;
  file: File;
}

const MAX_FILE_SIZE = 4 * 1024 * 1024; // 5MB in bytes

// Define Attachment interface for backward compatibility
interface Attachment {
  url: string;
  contentType?: string;
  name?: string;
}

// Extend the Message type to include attachments
interface ExtendedMessage extends UIMessage {
  // No additional properties needed - UIMessage now has parts array
}

export function MultimodalInput<TMessage extends UIMessage = UIMessage>({
  chatId,
  input,
  setInput,
  isLoading,
  stop,
  attachments,
  setAttachments,
  containsImages,
  messages,
  setMessages,
  append,
  handleSubmit,
  className,
  selectedModelId: initialSelectedModelId,
  onModelChange,
  onBrowseToggle,
  isBrowseEnabled,
  isAuthenticated,
}: MultimodalInputProps<TMessage>) {
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const { width } = useWindowSize();
  const router = useRouter();
  const { toast } = useToast();

  const [selectedModel, setSelectedModel] = useState<AIModelDisplayInfo>(
    () =>
      availableModels.find((model) => model.id === initialSelectedModelId) ||
      availableModels[0]
  );

  // Sync selectedModel when parent's selectedModelId changes
  useEffect(() => {
    const model = availableModels.find((m) => m.id === initialSelectedModelId);
    if (model) {
      setSelectedModel(model);
    }
  }, [initialSelectedModelId]);
  const [isModelDropdownOpen, setIsModelDropdownOpen] = useState(false);
  const [localStorageInput, setLocalStorageInput] = useLocalStorage(
    "input",
    ""
  );
  const [isUploading, setIsUploading] = useState(false);
  const [uploadQueue, setUploadQueue] = useState<UploadQueueItem[]>([]);
  const [previewAttachments, setPreviewAttachments] = useState<Attachment[]>(
    []
  );

  const submitForm = useCallback(() => {
    window.history.replaceState({}, "", `/apps/chat/${chatId}`);

    // Convert attachments to parts for v5 API
    const parts = attachments.map(attachment => ({
      type: "file" as const,
      url: attachment.url,
      mediaType: attachment.contentType || "image/jpeg",
    }));

    handleSubmit(undefined, {
      parts,
      selectedModelId: selectedModel.id,
      isBrowseEnabled,
    } as ChatRequestOptions & { selectedModelId?: string; isBrowseEnabled?: boolean });

    setAttachments([]);
    setLocalStorageInput("");

    if (width && width > 768) {
      textareaRef.current?.focus();
    }
  }, [
    attachments,
    handleSubmit,
    setAttachments,
    setLocalStorageInput,
    width,
    chatId,
    selectedModel.id,
    isBrowseEnabled,
  ]);

  useEffect(() => {
    if (textareaRef.current) {
      adjustHeight();
    }
  }, []);

  const adjustHeight = () => {
    if (textareaRef.current) {
      textareaRef.current.style.height = "auto";
      textareaRef.current.style.height = `${
        textareaRef.current.scrollHeight + 2
      }px`;
    }
  };

  useEffect(() => {
    if (textareaRef.current) {
      const domValue = textareaRef.current.value;
      // Prefer DOM value over localStorage to handle hydration
      const finalValue = domValue || localStorageInput || "";
      setInput(finalValue);
      adjustHeight();
    }
    // Only run once after hydration
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    setLocalStorageInput(input);
  }, [input, setLocalStorageInput]);

  const handleInput = (event: React.ChangeEvent<HTMLTextAreaElement>) => {
    setInput(event.target.value);
    adjustHeight();
  };

  const uploadFile = async (file: File, chatId: string) => {
    setIsUploading(true);
    const formData = new FormData();
    formData.append("file", file);
    formData.append("chatId", chatId);

    try {
      const response = await fetch(`/api/files/upload`, {
        method: "POST",
        body: formData,
      });

      if (response.ok) {
        const data = await response.json();
        return {
          url: data.url,
          name: data.path,
          contentType: file.type,
        };
      } else {
        const { error, details } = await response.json();
        console.error("Upload error:", { error, details });
        toast({
          title: "Upload error",
          description: error,
        });
      }
    } catch (error) {
      console.error("Upload failed:", error);
      toast({
        title: "Upload failed",
        description: "Failed to upload file, please try again!",
      });
    } finally {
      setIsUploading(false);
    }
  };

  const handleFileChange = useCallback(
    async (event: ChangeEvent<HTMLInputElement>) => {
      const files = Array.from(event.target.files || []);
      if (files.length === 0) return;

      // Process each file one by one
      for (const file of files) {
        // Check file size
        if (file.size > MAX_FILE_SIZE) {
          toast({
            title: `${file.name} exceeds 5MB limit`,
          });
          continue;
        }

        // Add single file to upload queue
        const queueItem = {
          id: crypto.randomUUID(),
          name: file.name,
          file,
        };
        setUploadQueue((prev) => [...prev, queueItem]);
        setIsUploading(true);

        try {
          const uploadedAttachment = await uploadFile(file, chatId);
          if (uploadedAttachment) {
            setAttachments((current) => [...current, uploadedAttachment]);
          }
        } catch (error) {
          console.error("Error uploading file:", error);
          toast({
            title: `Failed to upload ${file.name}`,
          });
        } finally {
          // Remove this file from the queue
          setUploadQueue((prev) =>
            prev.filter((item) => item.id !== queueItem.id)
          );
        }
      }
      setIsUploading(false);
    },
    [setAttachments, chatId]
  );

  useEffect(() => {
    // Load both cookies on mount
    const modelIdFromCookie = getCookie("model-id");
    const browseEnabledFromCookie = getCookie("browse-enabled");

    if (modelIdFromCookie) {
      const model = availableModels.find((m) => m.id === modelIdFromCookie);
      if (model) {
        setSelectedModel(model);
      }
    }

    if (browseEnabledFromCookie === "true" && onBrowseToggle) {
      onBrowseToggle(true);
    }
  }, [onBrowseToggle]);

  const handleModelSelect = (model: AIModelDisplayInfo) => {
    setSelectedModel(model);
    setCookie("model-id", model.id);
    setIsModelDropdownOpen(false);
    // Notify parent immediately
    onModelChange?.(model.id);
    // Disable browsing if the model doesn't support internet
    if (!AI_MODEL_DISPLAY[model.id].hasInternet && isBrowseEnabled) {
      onBrowseToggle?.(false);
      setCookie("browse-enabled", "false");
    }
  };

  const handleBrowseClick = useCallback(
    (e: React.MouseEvent) => {
      e.preventDefault();
      const newValue = !isBrowseEnabled;

      // If enabling browse and current model doesn't support internet, switch to Gemini 2.5 Flash
      if (newValue && !AI_MODEL_DISPLAY[selectedModel.id].hasInternet) {
        const geminiFlash = availableModels.find(m => m.id === "gemini-2.5-flash");
        if (geminiFlash) {
          handleModelSelect(geminiFlash);
          toast({
            title: "Switched to Gemini 2.5 Flash",
            description: "This model supports web search",
          });
        }
      }

      onBrowseToggle?.(newValue);
      setCookie("browse-enabled", newValue.toString());
    },
    [isBrowseEnabled, onBrowseToggle, selectedModel.id, handleModelSelect, toast]
  );

  const handleUnauthenticatedInteraction = () => {
    router.push("/auth"); // Redirect to auth page
  };

  const handleDeleteAttachment = (urlToDelete: string) => {
    setAttachments((current) =>
      current.filter((att) => att.url !== urlToDelete)
    );
  };

  if (!isAuthenticated) {
    return (
      <div className="w-full" onClick={handleUnauthenticatedInteraction}>
        <div className="cursor-pointer p-4 text-center border border-dashed rounded-lg">
          Sign in to send messages
        </div>
      </div>
    );
  }

  return (
    <div className="relative w-full flex flex-col gap-4 border-none">
      {input === "" &&
        attachments.length === 0 &&
        uploadQueue.length === 0 &&
        messages.length === 0 && (
          <div className="w-full px-1">
            <div className="text-sm text-muted-foreground/60 mb-4 font-medium">
              Get started with
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
              {suggestedActions.map((suggestedAction, index) => (
                <motion.button
                  initial={{ opacity: 0, y: 5 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: 5 }}
                  transition={{ delay: 0.1 * index }}
                  key={index}
                  onClick={async () => {
                    window.history.replaceState({}, "", `/chat/${chatId}`);
                    append({
                      role: "user",
                      content: suggestedAction.action,
                    });
                  }}
                  className="group flex items-center gap-3 p-3.5 
                    bg-background/50 hover:bg-blue-50/50 dark:hover:bg-blue-950/20 rounded-lg
                    border border-border/30 hover:border-blue-500/30
                    transition-all duration-200
                    hover:shadow-[0_0_1px_rgba(59,130,246,0.2)]
                    dark:hover:shadow-[0_0_1px_rgba(59,130,246,0.4)]"
                >
                  <span className="text-xl group-hover:scale-110 transition-transform duration-200">
                    {suggestedAction.icon}
                  </span>
                  <div className="flex flex-col items-start gap-0.5 text-left">
                    <span className="text-sm font-medium text-foreground/90">
                      {suggestedAction.title}
                    </span>
                    <span className="text-[11px] text-muted-foreground/70 line-clamp-1 group-hover:text-muted-foreground/90">
                      {suggestedAction.label}
                    </span>
                  </div>
                </motion.button>
              ))}
            </div>
          </div>
        )}

      {(attachments.length > 0 || uploadQueue.length > 0) && (
        <div className="flex flex-row gap-2 overflow-x-scroll items-end">
          {attachments.length > 0 && (
            <div className="flex flex-wrap gap-2 pb-2">
              {attachments.map((attachment) => (
                <div key={attachment.url} className="relative group">
                  <PreviewAttachment
                    attachment={attachment}
                    isUploading={isUploading}
                    showFileName={false}
                    size="small"
                  />
                  <button
                    onClick={() => handleDeleteAttachment(attachment.url)}
                    className="absolute top-2 right-2 p-1.5 rounded-full bg-black/50 text-white opacity-0 group-hover:opacity-100 transition-opacity"
                  >
                    <X className="h-4 w-4" />
                  </button>
                </div>
              ))}
            </div>
          )}

          {uploadQueue.map((queueItem) => (
            <PreviewAttachment
              key={queueItem.id}
              attachment={{
                url: "",
                name: queueItem.name,
                contentType: "",
              }}
              isUploading={true}
            />
          ))}
        </div>
      )}

      <textarea
        ref={textareaRef}
        placeholder="Send a message..."
        value={input}
        onChange={handleInput}
        className={cx(
          "min-h-[72px] w-full max-h-[calc(100dvh)]",
          "overflow-hidden resize-none px-4 pb-10 pt-4 rounded-2xl",
          "outline-none focus:outline-none focus:ring-0 border-0",
          className
        )}
        rows={3}
        autoFocus
        onKeyDown={(event) => {
          if (event.key === "Enter" && !event.shiftKey) {
            event.preventDefault();
            if (isLoading) {
              toast({
                title: "Please wait for the model to finish its response!",
              });
            } else {
              submitForm();
            }
          }
        }}
      />

      {isLoading ? (
        <Button
          className="rounded-full p-1.5 h-fit absolute bottom-2 right-2 m-0.5 border dark:border-zinc-600"
          onClick={(event) => {
            event.preventDefault();
            stop();
            setMessages((messages) => {
              const sanitized = sanitizeUIMessages(messages);
              return sanitized as TMessage[];
            });
          }}
        >
          <StopIcon size={14} />
        </Button>
      ) : (
        <Button
          className="rounded-full p-1.5 h-fit absolute bottom-2 right-2 m-0.5 border dark:border-zinc-600"
          onClick={(event) => {
            event.preventDefault();
            submitForm();
          }}
          disabled={input.length === 0 || uploadQueue.length > 0}
        >
          <ArrowUpIcon size={14} />
        </Button>
      )}

      <div className="absolute bottom-2.5 left-2 flex gap-2 items-center">
        <button
          type="button"
          onClick={handleBrowseClick}
          className={cn(
            "p-2 rounded-full transition-colors",
            isBrowseEnabled
              ? "bg-blue-500/10 text-blue-500"
              : "text-muted-foreground hover:text-foreground hover:bg-muted"
          )}
        >
          <Globe className="h-4 w-4" />
        </button>
        <div className="relative">
          <button
            type="button"
            className="cursor-pointer text-xs inline-flex items-center justify-center text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 text-muted-foreground hover:text-primary/80 h-7 rounded-md px-2 py-1"
            onClick={() => setIsModelDropdownOpen(!isModelDropdownOpen)}
          >
            <Image
              src={selectedModel.logo}
              alt={selectedModel.name}
              width={16}
              height={16}
              className="mr-1 rounded-sm"
            />
            {selectedModel.name}
            <svg
              className={`ml-1 h-4 w-4 transform transition-transform ${
                isModelDropdownOpen ? "rotate-180" : ""
              }`}
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
              xmlns="http://www.w3.org/2000/svg"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M19 9l-7 7-7-7"
              />
            </svg>
          </button>
          {isModelDropdownOpen && (
            <ul className="absolute bottom-full mb-2 z-10 w-40 rounded-md border border-zinc-200 dark:border-zinc-700 bg-white dark:bg-zinc-800 shadow-lg">
              {availableModels.map((model) => {
                const isDisabled =
                  (attachments.length > 0 || containsImages) &&
                  !AI_MODEL_DISPLAY[model.id].vision;

                return (
                  <li
                    key={model.id}
                    className={cn(
                      "flex items-center px-3 py-2 text-xs",
                      isDisabled
                        ? "cursor-not-allowed opacity-50 bg-zinc-100 dark:bg-zinc-700"
                        : "cursor-pointer text-zinc-600 dark:text-zinc-400 hover:bg-zinc-100 dark:hover:bg-zinc-700"
                    )}
                    onClick={() => !isDisabled && handleModelSelect(model)}
                    title={
                      isDisabled
                        ? "This model doesn't support image analysis"
                        : undefined
                    }
                  >
                    <Image
                      src={model.logo}
                      alt={model.name}
                      width={16}
                      height={16}
                      className="mr-2 rounded-sm"
                    />
                    {model.name}
                  </li>
                );
              })}
            </ul>
          )}
        </div>

        {AI_MODEL_DISPLAY[selectedModel.id].vision && (
          <label className="flex items-center gap-2 text-xs text-muted-foreground hover:text-foreground transition-colors cursor-pointer">
            <ImageIcon className="h-4 w-4 mr-1" />
            Upload Image
            <input
              type="file"
              accept="image/*"
              multiple
              className="hidden"
              onChange={(e) => handleFileChange(e)}
            />
          </label>
        )}
      </div>
    </div>
  );
}

