"use client";

import React, { useState } from "react";
import { motion } from "framer-motion";
import { FileIcon, UploadCloudIcon, LinkIcon } from "lucide-react";
import { Tabs, TabsList, TabsTrigger, TabsContent } from "@/components/ui/tabs";
import { Input } from "@/components/ui/input";
import Check from "@/components/(ui-components)/alerts/Check";
import { useDropzone } from "react-dropzone";

interface UploadDialogProps {
  fileUrl: string | null;
  fileName: string | null;
  setFileUrl: (url: string | null) => void;
  setFileName: (name: string | null) => void;
  handleUpload: (url: string | null, id: string | null) => Promise<void>;
}

const mainVariant = {
  initial: { x: 0, y: 0 },
  animate: { x: 20, y: -20, opacity: 0.9 },
};

function GridPattern() {
  const columns = 41;
  const rows = 11;
  return (
    <div className="flex bg-gray-100 dark:bg-neutral-900 flex-shrink-0 flex-wrap justify-center items-center gap-x-px gap-y-px scale-105">
      {Array.from({ length: rows }).map((_, row) =>
        Array.from({ length: columns }).map((_, col) => {
          const index = row * columns + col;
          return (
            <div
              key={`${col}-${row}`}
              className={`w-10 h-10 flex flex-shrink-0 rounded-[2px] ${
                index % 2 === 0
                  ? "bg-gray-50 dark:bg-neutral-950"
                  : "bg-gray-50 dark:bg-neutral-950 shadow-[0px_0px_1px_3px_rgba(255,255,255,1)_inset] dark:shadow-[0px_0px_1px_3px_rgba(0,0,0,1)_inset]"
              }`}
            />
          );
        })
      )}
    </div>
  );
}

interface UploadDialogProps {
  fileUrl: string | null;
  fileName: string | null;
  setFileUrl: (url: string | null) => void;
  setFileName: (name: string | null) => void;
  handleUpload: (url: string | null, id: string | null) => Promise<void>;
  handleUrlSubmit: () => Promise<void>;
  status: string;
  response: any;
}

const UploadDialog: React.FC<UploadDialogProps> = ({
  fileUrl,
  fileName,
  setFileUrl,
  setFileName,
  handleUpload,
  handleUrlSubmit,
  status,
  response,
}) => {
  const [activeTab, setActiveTab] = useState<string>("upload");
  const [uploading, setUploading] = useState<boolean>(false);
  const [success, setSuccess] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  const handleFileUpload = async (files: File[]) => {
    const file = files[0];
    if (!file) return;

    try {
      setUploading(true);
      setError(null);

      const formData = new FormData();
      formData.append("file", file);
      formData.append("uploadPath", "pdf");

      const response = await fetch("/pdf/api/upload", {
        method: "POST",
        body: formData,
      });

      if (!response.ok) {
        throw new Error(`Upload failed: ${response.statusText}`);
      }

      const data = await response.json();
      if (data.error) throw new Error(data.error);

      setFileUrl(data.url);
      setFileName(file.name);
      await handleUpload(data.url, data.documentId);
      setSuccess(true);
    } catch (error) {
      console.error("Upload error:", error);
      setError((error as Error).message);
    } finally {
      setUploading(false);
    }
  };

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    multiple: false,
    onDrop: handleFileUpload,
    accept: {
      "application/pdf": [".pdf"],
    },
    maxSize: 10 * 1024 * 1024, // 10MB
  });

  if (success) {
    return (
      <div className="w-full max-w-4xl mx-auto p-8">
        <Check>Your PDF has been uploaded successfully.</Check>
      </div>
    );
  }

  return (
    <div className="w-full max-w-4xl mx-auto">
      <Tabs
        value={activeTab}
        onValueChange={setActiveTab}
        className="w-full space-y-8"
      >
        <div className="flex justify-center">
          <TabsList className="grid grid-cols-2 w-[400px] h-12 items-center bg-neutral-100/50 dark:bg-neutral-900/50 backdrop-blur-sm rounded-full p-1">
            <TabsTrigger
              value="upload"
              className="rounded-full px-6 py-2 data-[state=active]:bg-white dark:data-[state=active]:bg-neutral-800 data-[state=active]:text-primary data-[state=active]:shadow-sm transition-all duration-300"
            >
              <div className="flex items-center gap-2">
                <UploadCloudIcon className="h-4 w-4" />
                <span className="font-medium">Upload PDF</span>
              </div>
            </TabsTrigger>
            <TabsTrigger
              value="url"
              className="rounded-full px-6 py-2 data-[state=active]:bg-white dark:data-[state=active]:bg-neutral-800 data-[state=active]:text-primary data-[state=active]:shadow-sm transition-all duration-300"
            >
              <div className="flex items-center gap-2">
                <LinkIcon className="h-4 w-4" />
                <span className="font-medium">Add URL</span>
              </div>
            </TabsTrigger>
          </TabsList>
        </div>

        <TabsContent value="upload">
          <div {...getRootProps()}>
            <motion.div
              whileHover="animate"
              className="p-10 group/file block rounded-lg cursor-pointer w-full relative overflow-hidden"
            >
              <div className="absolute inset-0 [mask-image:radial-gradient(ellipse_at_center,white,transparent)]">
                <GridPattern />
              </div>

              <div className="flex flex-col items-center justify-center">
                <input {...getInputProps()} />

                <p className="relative z-20 font-sans font-bold text-neutral-700 dark:text-neutral-300 text-base">
                  Upload PDF Document
                </p>
                <p className="relative z-20 font-sans font-normal text-neutral-400 dark:text-neutral-400 text-base mt-2">
                  {uploading
                    ? "Uploading..."
                    : isDragActive
                    ? "Drop your PDF here..."
                    : "Drag and drop your PDF here or click to browse"}
                </p>

                <div className="relative w-full mt-10 max-w-xl mx-auto">
                  <motion.div
                    layoutId="file-upload"
                    variants={mainVariant}
                    transition={{ type: "spring", stiffness: 300, damping: 20 }}
                    className="relative group-hover/file:shadow-2xl z-40 bg-white dark:bg-neutral-900 flex items-center justify-center h-32 mt-4 w-full max-w-[8rem] mx-auto rounded-md shadow-[0px_10px_50px_rgba(0,0,0,0.1)]"
                  >
                    {uploading ? (
                      <span className="loading loading-spinner loading-md" />
                    ) : isDragActive ? (
                      <FileIcon className="h-8 w-8 text-primary animate-pulse" />
                    ) : (
                      <FileIcon className="h-8 w-8 text-neutral-600 dark:text-neutral-300" />
                    )}
                  </motion.div>
                </div>

                <p className="relative z-20 text-xs text-neutral-400 dark:text-neutral-500 mt-6">
                  Supported format: PDF up to 10MB
                </p>
              </div>
            </motion.div>
          </div>
        </TabsContent>

        <TabsContent value="url">
          <div className="pb-10 w-full max-w-md mx-auto">
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.3 }}
              className="space-y-4 p-6 rounded-xl bg-white dark:bg-neutral-900 shadow-[0_0_1px_1px_rgba(0,0,0,0.05)] dark:shadow-[0_0_1px_1px_rgba(255,255,255,0.05)]"
            >
              <div className="space-y-3">
                <div>
                  <label className="text-sm font-medium text-neutral-600 dark:text-neutral-400">
                    Document Name
                  </label>
                  <div className="relative mt-1">
                    <Input
                      placeholder="my-document.pdf"
                      value={fileName || ""}
                      onChange={(e) => setFileName(e.target.value)}
                      disabled={uploading || status !== "Idle"}
                      className="h-10 pl-3 pr-9 bg-neutral-50 dark:bg-neutral-800/50 border-neutral-200 dark:border-neutral-700 rounded-lg focus:ring-1 focus:ring-primary/20 focus:border-primary transition-all duration-300"
                    />
                    <FileIcon className="absolute right-2.5 top-1/2 -translate-y-1/2 h-4 w-4 text-neutral-400" />
                  </div>
                </div>

                <div>
                  <label className="text-sm font-medium text-neutral-600 dark:text-neutral-400">
                    PDF URL
                  </label>
                  <div className="relative mt-1">
                    <Input
                      placeholder="https://example.com/document.pdf"
                      value={fileUrl || ""}
                      onChange={(e) => setFileUrl(e.target.value)}
                      disabled={uploading || status !== "Idle"}
                      className="h-10 pl-3 pr-9 bg-neutral-50 dark:bg-neutral-800/50 border-neutral-200 dark:border-neutral-700 rounded-lg focus:ring-1 focus:ring-primary/20 focus:border-primary transition-all duration-300"
                    />
                    <LinkIcon className="absolute right-2.5 top-1/2 -translate-y-1/2 h-4 w-4 text-neutral-400" />
                  </div>
                </div>
              </div>

              <button
                onClick={handleUrlSubmit}
                disabled={
                  uploading || !fileUrl || !fileName || status !== "Idle"
                }
                className="w-full h-10 mt-2 px-4 bg-neutral-600 hover:bg-neutral-700 text-white rounded-lg disabled:opacity-50 disabled:cursor-not-allowed transition-all duration-300 font-medium text-sm"
              >
                {status !== "Idle" ? (
                  <div className="flex items-center justify-center gap-2">
                    <span className="loading loading-spinner loading-sm" />
                    <span>{status}</span>
                  </div>
                ) : (
                  <div className="flex items-center justify-center gap-2">
                    <UploadCloudIcon className="h-4 w-4" />
                    <span>Add PDF from URL</span>
                  </div>
                )}
              </button>
            </motion.div>
          </div>
        </TabsContent>
      </Tabs>

      {error && (
        <motion.div
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          className="mt-4 p-4 bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 rounded-lg"
        >
          {error}
        </motion.div>
      )}

      {response?.error && (
        <motion.div
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          className="mt-4 p-4 bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 rounded-lg"
        >
          {response.error}
        </motion.div>
      )}
    </div>
  );
};

export default UploadDialog;

app/(apps)/pdf/components/your-files.tsx.content:
import React, { useState } from "react";
import { formatDistanceToNow } from "date-fns";
import { Button } from "@/components/ui/button";
import { TrashIcon } from "@radix-ui/react-icons";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import {
  Pagination,
  PaginationContent,
  PaginationItem,
  PaginationLink,
  PaginationNext,
  PaginationPrevious,
} from "@/components/ui/pagination";

import {
  Dialog,
  DialogTrigger,
  DialogContent,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/dialog";

interface YourFilesProps {
  documents: any[];
}

const YourFiles: React.FC<YourFilesProps> = ({ documents }) => {
  const [currentPage, setCurrentPage] = useState<number>(1);
  const [selectedDoc, setSelectedDoc] = useState<any>(null);
  const itemsPerPage = 5;

  const sortedDocuments = [...documents].sort(
    (a, b) =>
      new Date(b.created_at).getTime() - new Date(a.created_at).getTime()
  );

  const totalPages = Math.ceil(sortedDocuments.length / itemsPerPage);

  const handlePageChange = (page: number) => {
    setCurrentPage(page);
  };

  const currentDocuments = sortedDocuments.slice(
    (currentPage - 1) * itemsPerPage,
    currentPage * itemsPerPage
  );

  const handleDelete = async (documentId: string) => {
    const res = await fetch("/pdf/api/delete", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ documentId }),
    });
    if (res.ok) {
      // Refresh the documents list or handle the UI update
      setSelectedDoc(null);
      // Assuming you have a way to refresh the documents list, e.g., refetching from the server
      window.location.reload();
    }
  };

  return (
    <div className="w-full max-w-5xl mx-auto">
      <div className="space-y-2 mb-8">
        <h2 className="text-xl font-semibold tracking-tight">
          You have {documents.length} documents in your library
        </h2>
        <p className="text-base text-sm text-muted-foreground">
          You can view and delete your uploaded files here.
        </p>
      </div>

      {documents && (
        <div className="rounded-xl border border-border/40 bg-background shadow-sm">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead className="text-base font-medium text-sm text-muted-foreground">
                  File Name
                </TableHead>
                <TableHead className="text-base font-medium text-sm text-muted-foreground text-center">
                  Uploaded
                </TableHead>
                <TableHead className="text-base font-medium text-sm text-muted-foreground text-center hidden md:table-cell">
                  Size
                </TableHead>
                <TableHead className="w-[80px]" />
              </TableRow>
            </TableHeader>
            <TableBody>
              {currentDocuments.map((doc: any) => (
                <TableRow
                  key={doc.id}
                  className="hover:bg-muted/40 transition-colors duration-200"
                >
                  <TableCell className="py-4">
                    <a
                      href={`/pdf/document/${doc.id}`}
                      className="text-primary hover:text-primary/80 font-medium transition-colors duration-200"
                    >
                      {doc.file_name}
                    </a>
                  </TableCell>
                  <TableCell className="text-center text-muted-foreground">
                    {formatDistanceToNow(new Date(doc.created_at))} ago
                  </TableCell>
                  <TableCell className="hidden md:table-cell text-center text-muted-foreground">
                    {doc.size ? `${doc.size} MB` : "N/A"}
                  </TableCell>
                  <TableCell>
                    <Dialog>
                      <DialogTrigger asChild>
                        <Button
                          className="rounded-full size-9 p-0 hover:bg-destructive/10 hover:text-destructive transition-colors duration-200"
                          variant="ghost"
                          onClick={() => setSelectedDoc(doc)}
                        >
                          <TrashIcon className="w-4 h-4" />
                        </Button>
                      </DialogTrigger>
                      <DialogContent>
                        <DialogTitle>Confirm deletion</DialogTitle>
                        <DialogDescription>
                          Are you sure you want to delete this document? This
                          action cannot be undone.
                        </DialogDescription>
                        <DialogFooter>
                          <Button
                            className="bg-red-500 text-white hover:bg-red-400"
                            onClick={() => handleDelete(selectedDoc.id)}
                          >
                            Delete
                          </Button>
                        </DialogFooter>
                      </DialogContent>
                    </Dialog>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>

          <div className="py-4 px-2 border-t border-border/40">
            <Pagination>
              <PaginationContent>
                <PaginationItem>
                  <PaginationPrevious
                    href="#"
                    className="hover:bg-muted/40 transition-colors duration-200"
                    onClick={() =>
                      handlePageChange(Math.max(1, currentPage - 1))
                    }
                  />
                </PaginationItem>
                {Array.from({ length: totalPages }, (_, i) => (
                  <PaginationItem key={i}>
                    <PaginationLink
                      href="#"
                      className="hover:bg-muted/40 transition-colors duration-200"
                      onClick={() => handlePageChange(i + 1)}
                      isActive={i + 1 === currentPage}
                    >
                      {i + 1}
                    </PaginationLink>
                  </PaginationItem>
                ))}
                <PaginationItem>
                  <PaginationNext
                    href="#"
                    className="hover:bg-muted/40 transition-colors duration-200"
                    onClick={() =>
                      handlePageChange(Math.min(totalPages, currentPage + 1))
                    }
                  />
                </PaginationItem>
              </PaginationContent>
            </Pagination>
          </div>
        </div>
      )}
    </div>
  );
};

export default YourFiles;

app/(apps)/studio/api/route.ts.content:
/**
 * OpenAI Image Generation API Route
 *
 * Purpose:
 * This API route generates images using OpenAI's API based on a text prompt.
 * It supports three operation modes: generation, editing, and inpainting.
 *
 * How it works:
 * 1. Receives a request with a text prompt and optionally multiple images/mask
 * 2. Authenticates the user making the request
 * 3. Determines the operation mode based on provided inputs
 * 4. For edit/inpaint modes, creates temporary files from uploaded images
 * 5. Calls the OpenAI API with appropriate parameters based on operation mode
 * 6. Uploads the generated image to Cloudflare R2
 * 7. Stores the file record in Supabase
 * 8. Returns both the preview data and the public URL
 *
 * Operation modes:
 * - generate: Creates an image from text prompt only
 * - edit: Modifies up to 4 input images based on the prompt
 * - inpaint: Edits portions of an image defined by a mask
 *
 * Input parameters:
 * - prompt: Text description for the image to generate
 * - images: (Optional) Image files to use as input for editing/inpainting
 * - mask: (Optional) Mask image for inpainting
 *
 * Response:
 * - Success: Returns the generated image as both a data URL (preview) and a public URL
 * - Error: Returns appropriate error message and status code
 */

import { NextResponse, NextRequest } from "next/server";
import OpenAI, { toFile } from "openai";
import { openai } from "@/lib/clients/openai";
import fs from "fs";
import { authMiddleware } from "@/lib/middleware/authMiddleware";
import { uploadFile } from "@/lib/hooks/useFileUpload";
import { uploadToSupabase, reduceUserCredits, getUserCredits } from "@/lib/db/mutations";
import { toolConfig } from "@/app/(apps)/dalle/toolConfig";

// Define operation modes
type OperationMode = "generate" | "edit" | "inpaint";

export async function POST(request: NextRequest) {
  try {
    // Authenticate the user and get user data
    const authResponse = await authMiddleware(request);
    if (authResponse.status === 401) return authResponse;

    // Get user from the middleware-enhanced request
    const user = (request as any).user;

    // Parse request data
    let prompt: string = "";
    let inputImages: File[] = [];
    let maskImage: File | null = null;
    let operationMode: OperationMode = "generate"; // Default to generate

    if (request.headers.get("content-type")?.includes("multipart/form-data")) {
      const formData = await request.formData();
      prompt = formData.get("prompt") as string;

      const formImages = formData.getAll("images") as File[];
      // Use duck typing to check for File-like objects
      inputImages = formImages.filter(
        (item): item is File =>
          typeof item === "object" &&
          item !== null &&
          typeof item.name === "string" &&
          typeof item.arrayBuffer === "function"
      );

      const formMask = formData.get("mask");
      // Use duck typing to check for File-like objects
      if (
        typeof formMask === "object" &&
        formMask !== null &&
        typeof (formMask as File).name === "string" && // Type assertion needed here
        typeof (formMask as File).arrayBuffer === "function" // Type assertion needed here
      ) {
        maskImage = formMask as File; // Type assertion needed here
      }

      // Determine operation mode based on inputs
      if (inputImages.length > 0 && maskImage) {
        if (inputImages.length !== 1) {
          return NextResponse.json(
            {
              success: false,
              error:
                "Inpainting requires exactly one input image and one mask image.",
            },
            { status: 400 }
          );
        }
        operationMode = "inpaint";
        console.log("🟩 OpenAI Image API Start - Inpainting:", {
          prompt,
          imageName: inputImages[0].name,
          maskName: maskImage.name,
        });
      } else if (inputImages.length > 0) {
        if (inputImages.length > 4) {
          return NextResponse.json(
            {
              success: false,
              error: "Multi-image editing supports up to 4 input images.",
            },
            { status: 400 }
          );
        }
        operationMode = "edit";
        console.log("🟩 OpenAI Image API Start - Multi-Image Edit:", {
          prompt,
          imageCount: inputImages.length,
        });
      } else {
        operationMode = "generate";
        console.log("🟩 OpenAI Image API Start - Generate:", { prompt });
      }
    } else {
      // Handle JSON (text prompt only for generation)
      const body = await request.json();
      prompt = body.prompt;
      operationMode = "generate";
      console.log("🟩 OpenAI Image API Start - Generate (JSON):", { prompt });
    }

    if (!prompt) {
      return NextResponse.json(
        { success: false, error: "Prompt is required." },
        { status: 400 }
      );
    }

    // Check if paywall is enabled and validate user credits BEFORE processing
    if (toolConfig.paywall === true) {
      const userCredits = await getUserCredits(user.email);

      if (userCredits === null || userCredits === undefined) {
        return NextResponse.json(
          { success: false, error: "Unable to verify user credits" },
          { status: 400 }
        );
      }

      if (userCredits < toolConfig.credits) {
        return NextResponse.json(
          { 
            success: false,
            error: "Insufficient credits", 
            message: `You have ${userCredits} credits but need ${toolConfig.credits} credits to generate an image.`,
            creditsRequired: toolConfig.credits,
            creditsAvailable: userCredits
          },
          { status: 402 } // Payment Required
        );
      }
    }

    // --- OpenAI Image Generation/Editing Logic ---
    let resultB64Json: string | undefined;
    const tempFiles: string[] = []; // Keep track of temporary files

    try {
      if (operationMode === "generate") {
        console.log("🟨 Calling OpenAI images.generate...");
        const response = await openai.images.generate({
          model: "gpt-image-1",
          prompt: prompt,
          n: 1, // Generate one image
          size: "1024x1024", // Default size, adjust as needed
        });
        // Safely access the result
        if (response.data && response.data.length > 0) {
          resultB64Json = response.data[0].b64_json;
        }
        console.log("🟨 OpenAI images.generate response received.");
      } else if (operationMode === "edit") {
        console.log(
          "🟨 Preparing images for OpenAI images.edit (multi-image)..."
        );
        // Prepare images using temporary files and toFile
        const preparedImages = await Promise.all(
          inputImages.map(async (file) => {
            const tempFilePath = await createTempFile(file, tempFiles);
            // Ensure correct mimetype is passed to toFile
            return toFile(fs.createReadStream(tempFilePath), file.name, {
              type: file.type || "image/png", // Use original type or default
            });
          })
        );

        console.log("🟨 Calling OpenAI images.edit (multi-image)...");
        // The SDK should handle the array type based on documentation examples
        const response = await openai.images.edit({
          model: "gpt-image-1",
          // @ts-ignore - Suppress type error as SDK types might lag behind API capability
          image: preparedImages, // Pass the array of prepared files
          prompt: prompt,
          n: 1,
          size: "1024x1024",
        });
        // Safely access the result
        if (response.data && response.data.length > 0) {
          resultB64Json = response.data[0].b64_json;
        }
        console.log("🟨 OpenAI images.edit (multi-image) response received.");
      } else if (operationMode === "inpaint") {
        console.log(
          "🟨 Preparing image and mask for OpenAI images.edit (inpainting)..."
        );
        const imageFile = inputImages[0];
        const maskFile = maskImage as File; // Already validated it exists

        // Prepare image and mask using temporary files and toFile
        const tempImagePath = await createTempFile(imageFile, tempFiles);
        const preparedImage = await toFile(
          fs.createReadStream(tempImagePath),
          imageFile.name,
          // Ensure correct mimetype is passed to toFile
          { type: imageFile.type || "image/png" }
        );

        const tempMaskPath = await createTempFile(maskFile, tempFiles);
        const preparedMask = await toFile(
          fs.createReadStream(tempMaskPath),
          maskFile.name,
          // Ensure correct mimetype is passed to toFile
          { type: maskFile.type || "image/png" }
        );

        console.log("🟨 Calling OpenAI images.edit (inpainting)...");
        const response = await openai.images.edit({
          model: "gpt-image-1",
          image: preparedImage,
          mask: preparedMask,
          prompt: prompt,
          n: 1,
          size: "1024x1024",
        });
        // Safely access the result
        if (response.data && response.data.length > 0) {
          resultB64Json = response.data[0].b64_json;
        }
        console.log("🟨 OpenAI images.edit (inpainting) response received.");
      }
    } catch (apiError: any) {
      console.error("🟥 OpenAI API Error:", apiError);
      return NextResponse.json(
        {
          success: false,
          error: `OpenAI API request failed: ${
            apiError.message || "Unknown error"
          }`,
        },
        { status: 500 }
      );
    } finally {
      // Clean up temporary files
      cleanupTempFiles(tempFiles);
    }
    // --- End OpenAI Logic ---

    if (!resultB64Json) {
      return NextResponse.json(
        { success: false, error: "No image data received from OpenAI" },
        { status: 500 }
      );
    }

    // Construct the data URL for preview
    const imageDataUrl = `data:image/png;base64,${resultB64Json}`; // OpenAI returns PNG

    // Upload the generated image to Cloudflare R2
    const fileName = `openai-image-${Date.now()}.png`; // Use png extension
    const uploadResult = await uploadFile({
      imageUrl: imageDataUrl,
      uploadPath: "studio", // Keep using 'studio' path or change if needed
      fileName,
      skipMetadata: true, // Keep skipping R2 metadata if desired
    });

    console.log("🟦 Image uploaded to R2:", uploadResult);

    if (!uploadResult) {
      return NextResponse.json(
        { success: false, error: "Failed to upload image to storage" },
        { status: 500 }
      );
    }

    // Create request body for uploadToSupabase
    const requestBody = {
      prompt,
      email: user.email,
      operationMode,
      inputImageCount: inputImages.length,
      maskProvided: !!maskImage,
      model: "gpt-image-1",
    };

    // Store the response in Supabase using uploadToSupabase
    const supabaseResponse = await uploadToSupabase(
      requestBody,
      uploadResult.url,
      "studio", // toolPath
      "gpt-image-1" // aiModel
    );

    console.log("🟩 File record created:", supabaseResponse[0].id);

    // Reduce user credits (uncomment and adjust if paywall is enabled)
    if (toolConfig.paywall === true) {
      await reduceUserCredits(user.email, toolConfig.credits);
    }

    return NextResponse.json({
      success: true,
      output: {
        preview: imageDataUrl, // For immediate display in the UI
        publicUrl: uploadResult.url, // For permanent storage reference
      },
      fileId: supabaseResponse[0].id,
    });
  } catch (error: any) {
    console.error("🟥 OpenAI Image Route Error:", error);
    return NextResponse.json(
      {
        success: false,
        error: `Failed to process request: ${
          error.message || "Internal server error"
        }`,
      },
      { status: 500 }
    );
  }
}

// --- Helper Functions ---

/**
 * Creates a temporary file from a File object's buffer.
 * @param file The File object.
 * @param tempFiles Array to track created temp file paths.
 * @returns The path to the temporary file.
 */
async function createTempFile(
  file: File,
  tempFiles: string[]
): Promise<string> {
  const arrayBuffer = await file.arrayBuffer();
  const buffer = Buffer.from(arrayBuffer);
  // Use /tmp directory for serverless environments
  const tempFilePath = `/tmp/openai-upload-${Date.now()}-${Math.random()
    .toString(36)
    .substring(2, 15)}.${file.name.split(".").pop() || "tmp"}`;
  // Explicitly use Uint8Array to satisfy stricter type checking
  fs.writeFileSync(tempFilePath, new Uint8Array(buffer));
  tempFiles.push(tempFilePath); // Track the file for cleanup
  console.log(`💾 Created temp file: ${tempFilePath} for ${file.name}`);
  return tempFilePath;
}

/**
 * Deletes all temporary files tracked in the array.
 * @param tempFiles Array of temporary file paths.
 */
function cleanupTempFiles(tempFiles: string[]): void {
  console.log(`🧹 Cleaning up ${tempFiles.length} temporary files...`);
  for (const tempFile of tempFiles) {
    try {
      if (fs.existsSync(tempFile)) {
        // Check if file exists before unlinking
        fs.unlinkSync(tempFile);
        console.log(`🗑️ Deleted temp file: ${tempFile}`);
      }
    } catch (e) {
      console.error(`🟥 Error deleting temp file ${tempFile}:`, e);
    }
  }
  // Clear the array after attempting cleanup
  tempFiles.length = 0;
}

app/(apps)/studio/components/image-gener.content:
"use client";

import { useState, useRef, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Spinner } from "@/components/ui/spinner";
import { toast } from "sonner";
import {
  ArrowUp,
  Upload,
  X,
  ImageIcon,
  RefreshCw,
  ArrowUpRight,
  Plus,
  Wand2,
} from "lucide-react";
import { Card, CardContent } from "@/components/ui/card";
import { cn } from "@/lib/utils";
import cx from "classnames";
import {
  useDropzone,
  DropzoneRootProps,
  DropzoneInputProps,
} from "react-dropzone";
import { getRandomSuggestions } from "./image-suggestions";
import type { Suggestion } from "./image-suggestions";
import { motion } from "framer-motion";

// Grid pattern component for the upload area
function GridPattern() {
  const columns = 41;
  const rows = 11;
  return (
    <div className="flex bg-gray-100 dark:bg-neutral-900 flex-shrink-0 flex-wrap justify-center items-center gap-x-px gap-y-px scale-105">
      {Array.from({ length: rows }).map((_, row) =>
        Array.from({ length: columns }).map((_, col) => {
          const index = row * columns + col;
          return (
            <div
              key={`${col}-${row}`}
              className={`w-10 h-10 flex flex-shrink-0 rounded-[2px] ${
                index % 2 === 0
                  ? "bg-gray-50 dark:bg-neutral-950"
                  : "bg-gray-50 dark:bg-neutral-950 shadow-[0px_0px_1px_3px_rgba(255,255,255,1)_inset] dark:shadow-[0px_0px_1px_3px_rgba(0,0,0,1)_inset]"
              }`}
            />
          );
        })
      )}
    </div>
  );
}

const mainVariant = {
  initial: { x: 0, y: 0 },
  animate: { x: 20, y: -20, opacity: 0.9 },
};

// Define the props interface
interface ImageGeneratorProps {
  uploadedImages?: File[];
  onAddFiles?: (files: File[]) => void; // Callback to add files
  onRemoveImage?: (index: number) => void; // Callback to remove a file
  onClearAllImages?: () => void; // Callback to clear all files
  getRootProps?: <T extends DropzoneRootProps>(props?: T) => T;
  getInputProps?: <T extends DropzoneInputProps>(props?: T) => T;
  isDragActive?: boolean;
  isGenerating: boolean; // Receive generating state from parent
  error: string | null; // Receive error state from parent
  onSubmit: (prompt: string) => void; // Use parent's submit handler
}

export function ImageGenerator({
  uploadedImages = [],
  onAddFiles,
  onRemoveImage,
  onClearAllImages,
  getRootProps,
  getInputProps,
  isDragActive,
  isGenerating,
  error,
  onSubmit,
}: ImageGeneratorProps) {
  const [prompt, setPrompt] = useState("");
  const [imagePreviewUrls, setImagePreviewUrls] = useState<string[]>([]);
  const [suggestions, setSuggestions] = useState<Suggestion[]>(() =>
    getRandomSuggestions(uploadedImages.length > 0)
  );
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Internal dropzone setup ONLY if props aren't provided
  const internalDropzone = useDropzone({
    accept: {
      "image/*": [".jpeg", ".jpg", ".png", ".gif", ".webp"],
    },
    maxSize: 5 * 1024 * 1024, // 5MB
    onDrop: (acceptedFiles) => {
      if (onAddFiles) {
        onAddFiles(acceptedFiles);
      } else {
        console.warn("ImageGenerator: onAddFiles prop not provided.");
      }
    },
    onDropRejected: (fileRejections) => {
      const error = fileRejections[0]?.errors[0];
      if (error?.code === "file-too-large") {
        toast.error("File is too large. Maximum size is 5MB.");
      } else if (error?.code === "file-invalid-type") {
        toast.error("Invalid file type. Please upload only images.");
      } else {
        toast.error("Upload failed. Please try again.");
      }
    },
    noClick: true, // Prevent dropzone div itself from opening dialog
  });

  const finalGetRootProps = getRootProps || internalDropzone.getRootProps;
  const finalGetInputProps = getInputProps || internalDropzone.getInputProps;
  const finalIsDragActive =
    isDragActive !== undefined ? isDragActive : internalDropzone.isDragActive;

  // Generate image preview URLs
  useEffect(() => {
    const newPreviewUrls: string[] = [];
    let filesProcessed = 0;

    if (!Array.isArray(uploadedImages)) {
      setImagePreviewUrls([]);
      setSuggestions(getRandomSuggestions(false));
      return;
    }
    if (uploadedImages.length === 0) {
      setImagePreviewUrls([]);
      setSuggestions(getRandomSuggestions(false));
      return;
    }

    uploadedImages.forEach((file) => {
      if (!(file instanceof File)) {
        filesProcessed++;
        if (filesProcessed === uploadedImages.length)
          setImagePreviewUrls(newPreviewUrls);
        return;
      }
      const reader = new FileReader();
      reader.onload = () => {
        newPreviewUrls.push(reader.result as string);
        filesProcessed++;
        if (filesProcessed === uploadedImages.length)
          setImagePreviewUrls(newPreviewUrls);
      };
      reader.onerror = () => {
        filesProcessed++;
        if (filesProcessed === uploadedImages.length)
          setImagePreviewUrls(newPreviewUrls);
      };
      reader.readAsDataURL(file);
    });

    setSuggestions(getRandomSuggestions(uploadedImages.length > 0));

    // Cleanup
    return () => {
      newPreviewUrls.forEach((url) => {
        if (url.startsWith("blob:")) URL.revokeObjectURL(url);
      });
    };
  }, [uploadedImages]);

  const handleSubmitClick = () => {
    if (!isGenerating && prompt.trim()) {
      onSubmit(prompt); // Call parent's submit handler
    }
  };

  // Reintroduce explicit click handler for buttons/clickable areas
  const openFileDialog = () => {
    fileInputRef.current?.click();
  };

  // Handle file selection from hidden input
  const handleFileInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files && files.length > 0 && onAddFiles) {
      onAddFiles(Array.from(files));
    } else if (!onAddFiles) {
      console.warn("ImageGenerator: onAddFiles prop not provided.");
    }
    if (e.target) e.target.value = ""; // Reset file input
  };

  // Use the callbacks passed via props
  const removeUploadedImage = (index: number) => {
    if (onRemoveImage) {
      onRemoveImage(index);
    } else {
      console.warn("ImageGenerator: onRemoveImage prop not provided.");
    }
  };

  const clearAllUploadedImages = () => {
    if (onClearAllImages) {
      onClearAllImages();
    } else {
      console.warn("ImageGenerator: onClearAllImages prop not provided.");
    }
  };

  const refreshSuggestions = () => {
    setSuggestions(getRandomSuggestions(uploadedImages.length > 0));
  };

  const handleSuggestionSelect = (suggestionPrompt: string) => {
    setPrompt(suggestionPrompt);
    // Optionally trigger submit immediately after selection?
    // onSubmit(suggestionPrompt);
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSubmitClick();
    }
  };

  return (
    <div className="w-full mb-8 space-y-4">
      {/* Hidden file input managed by the ref */}
      <input
        {...finalGetInputProps()} // Use dropzone input props here
        ref={fileInputRef}
        className="hidden"
        onChange={handleFileInputChange}
        multiple
      />

      {/* Image upload section */}
      {uploadedImages.length > 0 ? (
        <div className="mb-5">
          <div className="flex justify-between items-center mb-3">
            <h3 className="text-sm font-medium text-zinc-700">
              Added Images ({uploadedImages.length})
            </h3>
            <button
              onClick={clearAllUploadedImages}
              className="text-xs text-red-500 hover:text-red-600 flex items-center gap-1"
            >
              <X className="h-3.5 w-3.5" /> Clear
            </button>
          </div>
          <div className="flex flex-wrap gap-3">
            {imagePreviewUrls.map((url, index) => (
              <div key={index} className="relative">
                <div className="relative w-24 h-24 rounded-lg overflow-hidden">
                  <img
                    src={url}
                    alt={`Uploaded ${index + 1}`}
                    className="w-full h-full object-cover"
                  />
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      removeUploadedImage(index);
                    }}
                    className="absolute top-1.5 right-1.5 p-1 bg-black/50 rounded-full text-white hover:bg-black/70"
                  >
                    <X className="h-3 w-3" />
                  </button>
                </div>
              </div>
            ))}
            <div
              className="w-24 h-24 flex items-center justify-center border border-dashed border-zinc-300 hover:border-zinc-400 rounded-lg cursor-pointer hover:bg-zinc-50 transition-colors"
              onClick={(e) => {
                e.stopPropagation();
                openFileDialog();
              }} // Stop propagation and open dialog
            >
              <div className="flex flex-col items-center">
                <Plus className="h-5 w-5 text-zinc-500" />
                <span className="text-xs text-zinc-500 mt-1">Add</span>
              </div>
            </div>
          </div>
        </div>
      ) : (
        <div
          {...finalGetRootProps({ className: "cursor-pointer" })}
          onClick={openFileDialog}
        >
          <motion.div
            whileHover="animate"
            className="p-8 group/file block rounded-lg w-full relative overflow-hidden"
          >
            <div className="absolute inset-0 [mask-image:radial-gradient(ellipse_at_center,white,transparent)]">
              <GridPattern />
            </div>

            <div className="flex flex-col items-center justify-center">
              <p className="relative z-20 font-sans font-bold text-neutral-700 dark:text-neutral-300 text-base">
                Add photos to edit
              </p>
              <p className="relative z-20 font-sans font-normal text-neutral-400 dark:text-neutral-400 text-base mt-2">
                {finalIsDragActive
                  ? "Drop your images here..."
                  : "Drag & drop your images here or click anywhere to browse"}
              </p>

              <div className="relative w-full mt-8 max-w-xl mx-auto">
                <motion.div
                  layoutId="image-upload"
                  variants={mainVariant}
                  transition={{ type: "spring", stiffness: 300, damping: 20 }}
                  className="relative group-hover/file:shadow-2xl z-40 bg-white dark:bg-neutral-900 flex items-center justify-center h-32 mt-4 w-full max-w-[8rem] mx-auto rounded-md shadow-[0px_10px_50px_rgba(0,0,0,0.1)]"
                >
                  {finalIsDragActive ? (
                    <ImageIcon className="h-8 w-8 text-indigo-500 animate-pulse" />
                  ) : (
                    <ImageIcon className="h-8 w-8 text-neutral-600 dark:text-neutral-300" />
                  )}
                </motion.div>
              </div>

              <p className="relative z-20 text-xs text-neutral-400 dark:text-neutral-500 mt-4">
                Supported formats: JPEG, PNG, GIF, WEBP up to 5MB
              </p>
            </div>
          </motion.div>
        </div>
      )}

      {/* Manual input field */}
      <div className="relative">
        <textarea
          placeholder={
            uploadedImages.length > 0
              ? "Describe how you want to edit or combine these images..."
              : "Describe the image you want to generate..."
          }
          value={prompt}
          onChange={(e) => setPrompt(e.target.value)}
          onKeyDown={handleKeyDown}
          className={cx(
            "min-h-[72px] w-full max-h-[calc(100dvh)]",
            "overflow-y-auto resize-none px-4 pb-16 pt-4 rounded-2xl",
            "outline-none focus:outline-none focus:ring-0 border-0",
            "bg-zinc-50/70 text-sm"
          )}
          rows={3}
          autoFocus
        />

        <div className="absolute bottom-4 right-4 z-10">
          <button
            onClick={handleSubmitClick}
            disabled={isGenerating || !prompt.trim()}
            className="p-1.5 rounded-full bg-black text-white hover:bg-zinc-800 
                     disabled:opacity-50 disabled:hover:bg-black transition-colors"
          >
            {isGenerating ? (
              <Spinner className="w-4 h-4" />
            ) : (
              <ArrowUp className="w-4 h-4" />
            )}
          </button>
        </div>
      </div>

      {/* Suggestions */}
      <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-3 mt-4">
        <div
          onClick={refreshSuggestions}
          className="flex items-center justify-center p-3 bg-zinc-50 rounded-lg hover:bg-zinc-100 cursor-pointer transition-colors"
        >
          <RefreshCw className="w-5 h-5 text-zinc-600" />
          <span className="ml-2 text-sm text-zinc-600">New ideas</span>
        </div>
        {suggestions.slice(0, 3).map((suggestion, index) => (
          <div
            key={index}
            onClick={() => handleSuggestionSelect(suggestion.prompt)}
            className={cn(
              "group p-4 bg-zinc-50 rounded-lg cursor-pointer",
              "hover:bg-zinc-100 transition-all",
              "flex flex-col justify-between",
              "min-h-[100px]"
            )}
          >
            <p className="text-sm text-zinc-700 line-clamp-2">
              {suggestion.text}
            </p>
            <div className="flex justify-end mt-2">
              <ArrowUpRight className="w-4 h-4 text-zinc-400 group-hover:text-zinc-600 transition-colors" />
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

