"use client";

import { useEffect, useState } from "react";
import { Dialog, DialogContent, DialogTrigger } from "@/components/ui/dialog";
import { format } from "date-fns";
import { motion } from "framer-motion";
import { ChevronLeft, ChevronRight, X } from "lucide-react";

// Assuming the Generation structure is similar enough
interface Generation {
  id: string;
  created_at: string;
  input_data: {
    prompt?: string;
    operationMode?: string; // Specific to studio?
    model?: string; // Specific to studio?
    [key: string]: any; // Allow other fields
  };
  output_data: string; // Assuming this is the image URL
  type: string; // Should be 'studio'
}

interface StudioGenerationsProps {
  generations: Generation[];
}

export function StudioGenerations({ generations }: StudioGenerationsProps) {
  const [selectedImageIndex, setSelectedImageIndex] = useState<number | null>(
    null
  );
  const [isDialogOpen, setIsDialogOpen] = useState(false);

  const showNext = () => {
    if (selectedImageIndex !== null) {
      setSelectedImageIndex((selectedImageIndex + 1) % generations.length);
    }
  };

  const showPrevious = () => {
    if (selectedImageIndex !== null) {
      setSelectedImageIndex(
        selectedImageIndex === 0
          ? generations.length - 1
          : selectedImageIndex - 1
      );
    }
  };

  const handleKeyDown = (e: KeyboardEvent) => {
    if (!isDialogOpen) return;
    if (e.key === "ArrowRight") showNext();
    else if (e.key === "ArrowLeft") showPrevious();
  };

  useEffect(() => {
    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [isDialogOpen, selectedImageIndex]);

  if (!generations || generations.length === 0) {
    return null; // Don't render anything if no generations
  }

  return (
    <div className="w-full py-12">
      <h2 className="text-xl font-semibold text-zinc-800 mb-6 px-4">
        Previously Generated Images
      </h2>
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6 px-4">
        {generations.map((gen, index) => {
          // Determine display info (model, prompt, etc.)
          const displayPrompt = gen.input_data.prompt || "Studio Generation";
          const displayModel =
            gen.input_data.model || gen.input_data.operationMode || "AI Studio";

          return (
            <Dialog
              key={gen.id}
              open={isDialogOpen && selectedImageIndex === index}
              onOpenChange={(open) => {
                setIsDialogOpen(open);
                if (open) setSelectedImageIndex(index);
                else setSelectedImageIndex(null);
              }}
            >
              <DialogTrigger asChild>
                <motion.div
                  className="relative rounded-xl overflow-hidden cursor-pointer will-change-transform"
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: index * 0.1 }}
                  whileHover={{ scale: 1.02 }}
                >
                  <div className="aspect-square">
                    <img
                      src={gen.output_data} // Use output_data for image src
                      alt={displayPrompt}
                      className="w-full h-full object-cover"
                    />
                  </div>

                  {/* Optional: Display model/mode */}
                  <div className="absolute top-3 left-3 px-3 py-1.5 rounded-full bg-black/50 text-white text-xs font-medium z-10">
                    {displayModel}
                  </div>

                  <div className="absolute inset-0 opacity-0 hover:opacity-100 transition-all duration-200 bg-gradient-to-t from-black/80 via-black/50 to-transparent p-4 flex flex-col justify-end">
                    <div className="text-white space-y-2">
                      <p className="text-sm font-light">
                        {format(new Date(gen.created_at), "MMM d, yyyy")}
                      </p>
                      <p className="text-sm font-medium line-clamp-3">
                        {displayPrompt}
                      </p>
                    </div>
                  </div>
                </motion.div>
              </DialogTrigger>

              <DialogContent className="max-w-7xl border-none p-6 shadow-none overflow-hidden bg-transparent">
                <motion.div
                  className="relative group"
                  initial={{ opacity: 0, scale: 0.95 }}
                  animate={{ opacity: 1, scale: 1 }}
                  exit={{ opacity: 0, scale: 0.95 }}
                  transition={{ duration: 0.2 }}
                >
                  <button
                    onClick={() => setIsDialogOpen(false)}
                    className="absolute top-4 -right-2 z-50 p-2 rounded-xl bg-white/10 backdrop-blur-sm border border-white/20 text-white hover:bg-white/20 transition-colors"
                  >
                    <X className="w-5 h-5" />
                  </button>
                  <button
                    onClick={showPrevious}
                    className="absolute -left-4 top-1/2 -translate-y-1/2 z-50 p-3 bg-white/10 backdrop-blur-sm border border-white/20 rounded-xl text-white hover:bg-white/20 transition-colors opacity-0 group-hover:opacity-100"
                  >
                    <ChevronLeft className="w-6 h-6" />
                  </button>
                  <button
                    onClick={showNext}
                    className="absolute -right-4 top-1/2 -translate-y-1/2 z-50 p-3 bg-white/10 backdrop-blur-sm border border-white/20 rounded-xl text-white hover:bg-white/20 transition-colors opacity-0 group-hover:opacity-100"
                  >
                    <ChevronRight className="w-6 h-6" />
                  </button>

                  <img
                    src={generations[selectedImageIndex ?? index].output_data}
                    alt={
                      generations[selectedImageIndex ?? index].input_data
                        .prompt || "Generated Image"
                    }
                    className="w-full h-auto max-h-[85vh] object-contain rounded-lg"
                  />

                  <div className="absolute -bottom-4 left-1/2 -translate-x-1/2 w-full max-w-3xl px-6 py-4 rounded-2xl bg-white/10 backdrop-blur-md backdrop-saturate-150 border border-white/20">
                    <div className="text-white space-y-4">
                      <div className="flex items-center gap-3">
                        <span className="px-3 py-1.5 rounded-full bg-white/10 backdrop-blur-sm border border-white/20 text-sm font-medium">
                          {generations[selectedImageIndex ?? index].input_data
                            .model ||
                            generations[selectedImageIndex ?? index].input_data
                              .operationMode ||
                            "AI Studio"}
                        </span>
                        <span className="text-sm text-white/70">
                          {format(
                            new Date(
                              generations[
                                selectedImageIndex ?? index
                              ].created_at
                            ),
                            "MMMM d, yyyy HH:mm"
                          )}
                        </span>
                      </div>
                      {generations[selectedImageIndex ?? index].input_data
                        .prompt && (
                        <p className="text-base font-light leading-relaxed">
                          {
                            generations[selectedImageIndex ?? index].input_data
                              .prompt
                          }
                        </p>
                      )}
                    </div>
                  </div>
                </motion.div>
              </DialogContent>
            </Dialog>
          );
        })}
      </div>
    </div>
  );
}

app/(apps)/vision/[slug]/page.tsx.content:
import DisplayOutput from "@/components/(apps)/dashboard/display-output";
import { toolConfig } from "../toolConfig";
import { Metadata } from "next";
import { getGenerationBySlug } from "@/lib/db/cached-queries";
import { notFound } from "next/navigation";

// This defines what information we need from the URL
type Props = {
  params: Promise<{ slug: string }>; // slug is the unique ID in the URL
};

// This function generates the page's metadata (title, description, etc.)
// It runs before the page loads and helps with SEO
export async function generateMetadata(props: Props): Promise<Metadata> {
  const params = await props.params;
  // Try to find the saved generation using its unique ID (slug)
  const generationData = await getGenerationBySlug(params.slug);

  // If we can't find the generation, use default metadata
  if (!generationData) {
    return {
      title: toolConfig.metadata.title,
      description: toolConfig.metadata.description,
      openGraph: {
        images: [toolConfig.metadata.og_image || ""], // Image shown when sharing on social media
      },
    };
  }

  // If we found the generation, use its data for the metadata
  return {
    title: generationData.title || toolConfig.metadata.title,
    description: generationData.description || toolConfig.metadata.description,
    openGraph: {
      images: [toolConfig.metadata.og_image || ""],
    },
  };
}

// Tell Next.js to not cache this page - always get fresh data
export const dynamic = "force-dynamic";

// The main page component that shows the generation result
export default async function Page(props: Props) {
  const params = await props.params;
  // Try to find the saved generation
  const generationData = await getGenerationBySlug(params.slug);

  // If we can't find it, show the 404 page
  if (!generationData) {
    notFound();
  }

  // Show the generation result using our DisplayOutput component
  return (
    <DisplayOutput toolConfig={toolConfig} generationData={generationData} />
  );
}

