app/(apps)/voice/components/settings-mod.content:
import React, { useState, useEffect } from "react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Slider } from "@/components/ui/slider";
import { Switch } from "@/components/ui/switch";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Label } from "@/components/ui/label";

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSettingsChange: (settings: any) => void;
  model: string;
  setModel: React.Dispatch<React.SetStateAction<string>>;
}

interface Model {
  model_id: string;
  name: string;
  can_use_style: boolean;
  can_use_speaker_boost: boolean;
}

export const SettingsModal: React.FC<SettingsModalProps> = ({
  isOpen,
  onClose,
  onSettingsChange,
  model,
  setModel,
}) => {
  const [stability, setStability] = useState(0.5);
  const [similarity, setSimilarity] = useState(0.5);
  const [styleExaggeration, setStyleExaggeration] = useState(0.5);
  const [speakerBoost, setSpeakerBoost] = useState(false);
  const [models, setModels] = useState<Model[]>([]);

  useEffect(() => {
    const fetchModels = async () => {
      try {
        const response = await fetch("/voice/api/models");
        if (!response.ok) {
          throw new Error("Failed to fetch models");
        }
        const data = await response.json();
        setModels(data);
        // Set the first model as default
        if (data.length > 0) {
          setModel(data[0].model_id);
        }
      } catch (error) {
        console.error("Error fetching models:", error);
      }
    };

    fetchModels();
  }, []);

  useEffect(() => {
    onSettingsChange({
      stability,
      similarity,
      styleExaggeration,
      speakerBoost,
      model,
    });
  }, [
    stability,
    similarity,
    styleExaggeration,
    speakerBoost,
    model,
    onSettingsChange,
  ]);

  const selectedModel = models.find((m) => m.model_id === model);

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="sm:max-w-[425px]">
        <DialogHeader>
          <DialogTitle>Voice Settings</DialogTitle>
        </DialogHeader>
        <div className="grid gap-4 py-4">
          <div className="grid grid-cols-4 items-center gap-4">
            <Label htmlFor="stability" className="text-right">
              Stability
            </Label>
            <Slider
              id="stability"
              min={0}
              max={1}
              step={0.1}
              value={[stability]}
              onValueChange={([value]) => setStability(value)}
              className="col-span-3"
            />
          </div>
          <div className="grid grid-cols-4 items-center gap-4">
            <Label htmlFor="similarity" className="text-right">
              Similarity
            </Label>
            <Slider
              id="similarity"
              min={0}
              max={1}
              step={0.1}
              value={[similarity]}
              onValueChange={([value]) => setSimilarity(value)}
              className="col-span-3"
            />
          </div>
          {selectedModel?.can_use_style && (
            <div className="grid grid-cols-4 items-center gap-4">
              <Label htmlFor="style" className="text-right">
                Style
              </Label>
              <Slider
                id="style"
                min={0}
                max={1}
                step={0.1}
                value={[styleExaggeration]}
                onValueChange={([value]) => setStyleExaggeration(value)}
                className="col-span-3"
              />
            </div>
          )}
          {selectedModel?.can_use_speaker_boost && (
            <div className="flex items-center space-x-2">
              <Switch
                id="speaker-boost"
                checked={speakerBoost}
                onCheckedChange={setSpeakerBoost}
              />
              <Label htmlFor="speaker-boost">Speaker Boost</Label>
            </div>
          )}
          <div className="flex items-center space-x-2">
            <Label htmlFor="model">Model</Label>
            <Select onValueChange={setModel} value={model}>
              <SelectTrigger className="w-[180px]">
                <SelectValue placeholder="Select model" />
              </SelectTrigger>
              <SelectContent>
                {models.map((modelOption) => (
                  <SelectItem
                    key={modelOption.model_id}
                    value={modelOption.model_id}
                  >
                    {modelOption.name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
};

app/(apps)/voice/components/text-to-spee.content:
"use client";

import React, { useState, useEffect } from "react";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { SettingsModal } from "./settings-modal";
import { AudioPlayer } from "./audio-player";
import { AudioWaveformIcon, SettingsIcon } from "lucide-react";

export const TextToSpeechTab: React.FC = () => {
  const [model, setModel] = useState("");
  const [text, setText] = useState("");
  const [voice, setVoice] = useState("");
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [settings, setSettings] = useState({});
  const [voices, setVoices] = useState<{ voice_id: string; name: string }[]>(
    []
  );

  useEffect(() => {
    const fetchVoices = async () => {
      try {
        const response = await fetch("/voice/api/voices");
        if (!response.ok) {
          throw new Error("Failed to fetch voices");
        }
        const data = await response.json();
        const voicesData = data.voices.map((v: any) => ({
          voice_id: v.voice_id,
          name: v.name,
        }));
        setVoices(voicesData);

        // Set the first voice as default
        if (voicesData.length > 0) {
          setVoice(voicesData[0].voice_id);
        }
      } catch (error) {
        console.error("Error fetching voices:", error);
      }
    };

    fetchVoices();
  }, []);
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);

    try {
      const response = await fetch("/voice/api/text-to-speech", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ text, voice, settings }),
      });

      if (!response.ok) {
        throw new Error("Failed to generate audio");
      }

      const data = await response.json();
      setAudioUrl(data.url);
    } catch (error) {
      console.error("Error generating audio:", error);
      alert("Failed to generate audio. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="space-y-4 w-full">
      <form onSubmit={handleSubmit} className="space-y-2">
        <Textarea
          value={text}
          onChange={(e) => setText(e.target.value)}
          placeholder="Enter text to convert to speech"
          className="min-h-[100px]"
        />
        <div className="flex items-center justify-between space-x-2">
          <div className="flex items-center space-x-2">
            <Select onValueChange={setVoice} value={voice}>
              <SelectTrigger className="w-[200px]">
                <SelectValue placeholder="Select voice" />
              </SelectTrigger>
              <SelectContent>
                {voices.map((voice) => (
                  <SelectItem key={voice.voice_id} value={voice.voice_id}>
                    {voice.name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
            <button
              className="rounded-xl btn btn-md btn-ghost text-primary"
              type="button"
              onClick={() => setIsSettingsOpen(true)}
            >
              <SettingsIcon className="w-4" />
            </button>
          </div>
          <Button
            type="submit"
            disabled={isLoading || !voice || !model || !text.trim()}
            className="text-primary-content"
          >
            <AudioWaveformIcon className="w-4 mr-2" />
            {isLoading ? "Generating..." : "Generate audio"}
          </Button>
        </div>
      </form>
      {audioUrl && <AudioPlayer audioUrl={audioUrl} />}
      <SettingsModal
        isOpen={isSettingsOpen}
        onClose={() => setIsSettingsOpen(false)}
        onSettingsChange={setSettings}
        model={model}
        setModel={setModel}
      />
    </div>
  );
};

app/api/auth/google/route.ts.content:
import { NextRequest, NextResponse } from "next/server";
import { createClient } from "@/lib/utils/supabase/server";
import { redirectToModal } from "@/config";
import { revalidateTag } from "next/cache";

/**
 * Handles Google OAuth authentication requests
 * 
 * @param request NextRequest containing redirect URL
 * @returns JSON response with OAuth URL or error
 * 
 * Flow:
 * 1. Gets current session (if any) to invalidate its cache
 * 2. Initiates Google OAuth process
 * 3. Invalidates relevant cache entries
 * 4. Returns OAuth URL for client redirect
 */
export async function POST(request: NextRequest) {
  const supabase = await createClient();

  const { next } = await request.json();

  try {
    // Get current session to handle cache invalidation for user switching
    const { data: { session: oldSession } } = await supabase.auth.getSession();

    // Initiate OAuth sign in process
    const { data, error } = await supabase.auth.signInWithOAuth({
      provider: "google",
      options: {
        redirectTo: redirectToModal(next),
      },
    });

    if (error) throw error;

    if (data.url) {
      // Invalidate generic session tag for backwards compatibility
      revalidateTag("session");

      // If there was a previous session, invalidate its specific cache
      // This prevents stale data when switching between accounts
      if (oldSession?.user?.id) {
        const cacheKey = `session_${oldSession.user.id}_${oldSession.access_token.slice(-10)}`;
        revalidateTag(cacheKey);
      }

      return NextResponse.json({
        status: "Success",
        url: data.url,
      });
    } else {
      throw new Error("No URL returned from Supabase");
    }
  } catch (error) {
    // Handle known errors with specific messages
    if (error instanceof Error) {
      return NextResponse.json(
        { status: "Error", message: error.message },
        { status: 500 }
      );
    } else {
      // Handle unknown errors with generic message
      return NextResponse.json(
        { status: "Error", message: "An unknown error occurred" },
        { status: 500 }
      );
    }
  }
}

app/api/auth/signout/route.ts.content:
import { createClient } from "@/lib/utils/supabase/server";
import { NextResponse } from "next/server";
import { revalidateTag } from "next/cache";

/**
 * Handles user sign out requests
 * 
 * @returns Redirect response to auth page
 * 
 * Flow:
 * 1. Gets current session before signing out
 * 2. Signs out from Supabase
 * 3. Invalidates three types of cached data:
 *    - Session data (from getSession)
 *    - User profile data (from getUser)
 *    - User credits data (from getUserCredits)
 * 4. Redirects to auth page
 */
export async function POST() {
  const supabase = await createClient();

  // Get current session before signing out
  // This is necessary to access session data for cache invalidation
  const { data: { session } } = await supabase.auth.getSession();

  // Sign out from Supabase auth
  await supabase.auth.signOut();

  // If there was an active session, invalidate all related caches
  if (session) {
    // Invalidate session cache (used by getSession)
    const cacheKey = `session_${session.user.id}_${session.access_token.slice(-10)}`;
    revalidateTag(cacheKey);

    // Invalidate user-specific caches if user data exists
    if (session.user) {
      // Invalidate user profile cache (used by getUser)
      revalidateTag(`user_${session.user.email}`);
      // Invalidate user credits cache (used by getUserCredits)
      revalidateTag(`user_${session.user.id}_credits`);
    }
  }

  // Use absolute URL for redirect to ensure correct routing
  const url = new URL("/auth", process.env.PRODUCTION_URL || "http://localhost:3000");
  return NextResponse.redirect(url.toString());
}

app/api/payments/lemonsqueezy/route.ts.content:
import crypto from "crypto";
import { type Payload } from "@/lib/types/lemonsqueezy";
import {
  checkUserProfile,
  updateUserProfile,
  updatePurchasesTable,
  addUserCredits,
} from "@/lib/db/payments";

const isError = (error: unknown): error is Error => {
  return error instanceof Error;
};

// Ensure dynamic content generation for each request
export const dynamic = "force-dynamic";

/**
 * Handles POST requests for LemonSqueezy webhook events.
 * This function is responsible for processing LemonSqueezy webhook events,
 * particularly the 'order_created' event.
 *
 * @param request - The incoming request object
 * @returns A Response object indicating the result of the webhook processing
 */
export async function POST(request: Request) {
  if (!process.env.LEMON_SQUEEZY_WEBHOOK_SECRET) {
    return new Response(
      "Please set your LemonSqueezy webhook secret in your .env file.",
      {
        status: 500,
      }
    );
  }

  try {
    // Verify the webhook signature
    const secret = process.env.LEMON_SQUEEZY_WEBHOOK_SECRET;
    const text = await request.text();
    const hmac = crypto.createHmac("sha256", secret || "");
    const digest = Buffer.from(hmac.update(text).digest("hex"), "utf8");
    const signature = Buffer.from(
      request.headers.get("x-signature") as string,
      "utf8"
    );

    if (!crypto.timingSafeEqual(digest, signature)) {
      return new Response("Invalid signature.", {
        status: 400,
      });
    }

    const payload = JSON.parse(text);

    const {
      meta: { event_name: eventName },
      data: { attributes, id },
    } = payload as Payload;

    const userEmail = attributes.user_email;

    // Check if the user exists in the database
    const UserProfile = await checkUserProfile(userEmail);

    switch (eventName) {
      case "order_created":
        await handleOrderCreated(attributes, id, UserProfile, userEmail);
        break;
      case "order_refunded":
      case "subscription_created":
        // Do stuff here if you are using subscriptions
        console.log(attributes);
        break;
      case "subscription_cancelled":
      case "subscription_resumed":
      case "subscription_expired":
      case "subscription_paused":
      case "subscription_unpaused":
      case "subscription_payment_failed":
      case "subscription_payment_success":
      case "subscription_payment_recovered":
      default:
        throw new Error(`Unhandled event: ${eventName}`);
    }
  } catch (error: unknown) {
    if (isError(error)) {
      return new Response(`Webhook error: ${error.message}`, {
        status: 400,
      });
    }

    return new Response("Webhook error", {
      status: 400,
    });
  }

  return new Response(null, {
    status: 200,
  });
}

/**
 * Processes a created order event.
 * This function determines the purchase type, updates the user's profile,
 * and records the purchase in the database.
 *
 * @param attributes - The attributes of the order
 * @param id - The order ID
 * @param UserProfile - The user's profile (if exists)
 * @param userEmail - The user's email
 * @returns A Response object or undefined
 */
async function handleOrderCreated(
  attributes: any,
  id: string,
  UserProfile: any,
  userEmail: string
) {
  if ("first_order_item" in attributes) {
    let purchaseType: string | null = null;

    // Check which product was purchased
    const variantId = attributes.first_order_item.variant_id;
    const status = attributes.status;

    // Define purchase type based on variant ID
    switch (variantId) {
      case 373993:
        purchaseType = "anotherwrapper-core";
        break;
      case 373998:
        purchaseType = "anotherwrapper-premium";
        break;
      case 452443:
        purchaseType = "anotherwrapper-enterprise";
        break;
      case 404332:
        purchaseType = "credits-small";
        break;
      case 404333:
        purchaseType = "credits-large";
        break;
      default:
        console.log("Unrecognized product ID, no update applied.");
        return new Response("Unrecognized product ID, no update applied.", {
          status: 200,
        });
    }

    // Always store the purchase in the database
    await updatePurchasesTable(
      userEmail,
      id,
      attributes,
      purchaseType,
      "lemonsqueezy"
    );

    // If no user is found with this email, return a message
    if (!UserProfile) {
      console.log("No user found with this email");
      return new Response(
        "No user found with this email, but purchase was stored in database!",
        {
          status: 200,
        }
      );
    }

    // Update the user profile and add credits if applicable
    if (status === "paid") {
      await updateUserProfile(userEmail, purchaseType);

      if (purchaseType === "credits-small") {
        await addUserCredits(userEmail, 50);
      } else if (purchaseType === "credits-large") {
        await addUserCredits(userEmail, 100);
      }
    }

    console.log("Purchased product: ", variantId);
  }
}

app/api/payments/stripe/route.ts.content:
import Stripe from "stripe";
import { NextRequest, NextResponse } from "next/server";
import {
  checkUserProfile,
  updateUserProfile,
  updatePurchasesTable,
  addUserCredits,
} from "@/lib/db/payments";

// Initialize Stripe with the secret key from environment variables
const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!, {
  apiVersion: "2025-02-24.acacia",
});

// Ensure dynamic content generation for each request
export const dynamic = "force-dynamic";

/**
 * Handles POST requests for Stripe webhook events.
 * This function is responsible for processing Stripe webhook events,
 * particularly the 'checkout.session.completed' event.
 *
 * @param request - The incoming request object
 * @returns A JSON response indicating the result of the webhook processing
 */
export async function POST(request: NextRequest) {
  const payload = await request.text();
  const signature = request.headers.get("stripe-signature")!;

  let event: Stripe.Event;

  try {
    // Construct the Stripe event asynchronously
    event = await stripe.webhooks.constructEventAsync(
      payload,
      signature,
      process.env.STRIPE_WEBHOOK_SECRET!
    );
  } catch (err: any) {
    console.error(`Webhook Error: ${err.message}`);
    return NextResponse.json({ error: err.message }, { status: 400 });
  }

  // Handle the 'checkout.session.completed' event
  if (event.type === "checkout.session.completed") {
    const session = event.data.object as Stripe.Checkout.Session;
    await handleCheckoutSessionCompleted(session);
  }

  return NextResponse.json({ received: true });
}

/**
 * Processes a completed checkout session.
 * This function retrieves product information, updates the user's profile,
 * and records the purchase in the database.
 *
 * @param session - The completed Stripe Checkout Session object
 */
async function handleCheckoutSessionCompleted(
  session: Stripe.Checkout.Session
) {
  const userEmail = session.customer_details?.email;
  if (!userEmail) {
    console.log("No user email found in the session");
    return;
  }

  // Retrieve line items from the session
  const lineItems = await stripe.checkout.sessions.listLineItems(session.id);

  if (lineItems.data.length === 0) {
    console.log("No line items found in the session");
    return;
  }

  // Get the first item (assuming one product per checkout)
  const item = lineItems.data[0];

  if (!item.price?.product) {
    console.log("No product information found in the line item");
    return;
  }

  // Extract the product ID
  const productId =
    typeof item.price.product === "string"
      ? item.price.product
      : item.price.product.id;

  let purchaseType: string | null = null;

  // Try to get purchase type from session metadata
  if (session.metadata && session.metadata.type) {
    purchaseType = session.metadata.type;
  }

  // If not found in session metadata, fetch product details
  if (!purchaseType) {
    const product = await stripe.products.retrieve(productId);

    if (product.metadata && product.metadata.type) {
      purchaseType = product.metadata.type;
    }
  }

  if (!purchaseType) {
    console.log("Unable to determine purchase type from metadata");
    return;
  }

  // Check if the user profile exists based on the email used for purchase
  const userProfile = await checkUserProfile(userEmail);

  // Record the purchase in the database
  await updatePurchasesTable(
    userEmail,
    session.id,
    session,
    purchaseType,
    "stripe"
  );

  if (!userProfile) {
    console.log(
      "No user found with this email, but purchase was stored in database!"
    );
    return;
  }

  // Update the user's profile with the new purchase type
  await updateUserProfile(userEmail, purchaseType);

  // Add credits for credit products
  if (purchaseType === "credits-small") {
    await addUserCredits(userEmail, 50);
  } else if (purchaseType === "credits-large") {
    await addUserCredits(userEmail, 100);
  }

  console.log("User profile updated successfully");
}

app/auth/confirm/hash/route.ts.content:
import { type EmailOtpType } from "@supabase/supabase-js";
import { type NextRequest, NextResponse } from "next/server";

import { createClient } from "@/lib/utils/supabase/server";

export async function GET(request: NextRequest) {
  const { searchParams } = new URL(request.url);
  const token_hash = searchParams.get("token_hash");
  const type = searchParams.get("type") as EmailOtpType | null;
  const next = searchParams.get("next") ?? "/";

  const redirectTo = request.nextUrl.clone();
  redirectTo.pathname = next;
  redirectTo.searchParams.delete("token_hash");
  redirectTo.searchParams.delete("type");

  console.log("Request URL:", request.url);
  console.log("Token Hash:", token_hash);
  console.log("Type:", type);
  console.log("Next:", next);
  console.log("Redirect To (before verification):", redirectTo.href);

  if (token_hash && type) {
    const supabase = await createClient();

    const { error } = await supabase.auth.verifyOtp({
      type,
      token_hash,
    });

    console.log("Verification Error:", error);

    if (!error) {
      redirectTo.searchParams.delete("next");
      console.log(
        "Redirect To (after successful verification):",
        redirectTo.href
      );
      return NextResponse.redirect(redirectTo);
    }
  }

  // return the user to an error page with some instructions
  redirectTo.pathname = "/error";
  console.log("Redirect To (error case):", redirectTo.href);
  return NextResponse.redirect(redirectTo);
}

