import { NextResponse } from "next/server";
import s3 from "@/lib/clients/cloudflare";
import { createClient } from "@/lib/utils/supabase/server";
import { DeleteObjectCommand } from "@aws-sdk/client-s3";
import { revalidateTag } from "next/cache";

/**
 * API Route: Handles deletion of audio recordings and associated data.
 *
 * **Process:**
 * 1. Authenticates the user.
 * 2. Retrieves the recording details from the database.
 * 3. Deletes the audio file from cloud storage.
 * 4. Removes the recording entry from the database.
 * 5. Revalidates related cache tags for UI consistency.
 *
 * **Note:**
 * - Deletes both the physical file and database records.
 * - Cascading deletes should handle associated transcripts and summaries.
 * - Revalidates cache tags for recording, transcript, summary, and user's recordings list.
 *
 * @param {Request} request - The incoming request containing the recordingId.
 * @returns {Promise<NextResponse>} JSON response indicating success or failure.
 */
export async function POST(request: any) {
  const { recordingId } = await request.json();
  const supabase = await createClient();

  // Authenticate user
  const {
    data: { user },
  } = await supabase.auth.getUser();

  const userId = user?.id;

  if (!userId) {
    return NextResponse.json(
      { error: "You must be logged in to delete audio" },
      { status: 401 }
    );
  }

  // Retrieve recording details and verify ownership
  const { data: recording, error } = await supabase
    .from("recordings")
    .select("*")
    .eq("id", recordingId)
    .eq("user_id", userId)
    .single();

  if (error || !recording) {
    return NextResponse.json(
      { error: "Recording not found or access denied" },
      { status: 404 }
    );
  }

  // Prepare delete command for cloud storage
  const deleteCommand = new DeleteObjectCommand({
    Bucket: process.env.STORAGE_BUCKET,
    Key: recording.file_url.split(`${process.env.STORAGE_PUBLIC_URL}/`)[1],
  });

  try {
    // Delete file from cloud storage and database record
    await s3.send(deleteCommand);
    const { error: deleteError } = await supabase
      .from("recordings")
      .delete()
      .eq("id", recordingId)
      .eq("user_id", userId);

    if (deleteError) {
      throw new Error("Failed to delete from database");
    }

    // Revalidate cache tags
    revalidateTag(`recording_${recordingId}`);
    revalidateTag(`transcript_${recordingId}`);
    revalidateTag(`summary_${recordingId}`);
    revalidateTag(`user_${userId}_recordings`);

    return NextResponse.json({ success: true }, { status: 200 });
  } catch (error) {
    console.error("Error deleting recording:", error);
    return NextResponse.json(
      { error: "Failed to delete recording" },
      { status: 500 }
    );
  }
}

app/(apps)/audio/api/summarize/route.ts.content:
import { openai } from "@ai-sdk/openai";
import { generateObject } from "ai";
import { createClient } from "@/lib/utils/supabase/server";
import { NextResponse, NextRequest } from "next/server";
import { toolConfig } from "@/app/(apps)/audio/toolConfig";
import { z } from "zod";
/**
 * Schema for structured output from the AI model.
 * Defines the expected format of the summary, including:
 * - title: A descriptive title for the voice message
 * - summary: A third-person perspective summary
 * - actionItems: A list of explicit action items
 */
const SummarizeSchema = z.object({
  title: z
    .string()
    .min(5)
    .describe(
      "A short descriptive title summarizing the main topic of the voice message"
    ),
  summary: z
    .string()
    .describe(
      "A summary from a third-party perspective describing what is discussed in the voice message."
    ),
  actionItems: z
    .array(z.string())
    .nonempty()
    .describe(
      "A clear and concise list of action items derived from the voice note. Ensure all action items are explicitly stated and resolved if nested"
    ),
});

/**
 * API Route: Generates a structured summary of transcribed audio using Groq AI.
 *
 * **Process:**
 * 1. Authenticates the user.
 * 2. Processes the transcript using Groq AI to generate:
 *    - A descriptive title
 *    - A comprehensive summary
 *    - A list of action items
 * 3. Stores the summary in the database.
 * 4. Updates the recording title.
 * 5. Returns the summary ID.
 *
 * @param {NextRequest} request - The incoming request containing the transcript and recordingId.
 * @returns {Promise<NextResponse>} JSON response containing the summary ID.
 */
export async function POST(request: NextRequest) {
  const supabase = await createClient();

  // Authenticate user
  const {
    data: { user },
  } = await supabase.auth.getUser();

  const userId = user?.id;

  if (!userId) {
    return NextResponse.json({
      error: "You must be logged in to ingest data",
    });
  }

  try {
    const requestBody = await request.json();
    const { transcript, recordingId } = requestBody;

    if (!recordingId) {
      return NextResponse.json({
        error: "Document ID is required",
      });
    }

    // Generate structured summary using xAI instead of LangChain
    const { object: responseData } = await generateObject({
      model: openai(toolConfig.aiModel),
      schema: SummarizeSchema,
      system: toolConfig.systemMessage,
      prompt: transcript,
    });

    console.log("Response from xAI:", responseData);

    const { title, summary, actionItems } = responseData;

    // Keep the same database operations
    const { data: summaryData, error: summaryError } = await supabase
      .from("summaries")
      .insert({
        recording_id: recordingId,
        summary: summary,
        action_items: actionItems,
        title: title,
        model: toolConfig.aiModel,
      })
      .select();

    if (summaryError) {
      throw new Error(summaryError.message);
    }

    console.log("Summary inserted successfully:", summaryData);

    const { data: recordingData, error: recordingError } = await supabase
      .from("recordings")
      .update({ title: title })
      .eq("id", recordingId)
      .select();

    if (recordingError) {
      throw new Error(recordingError.message);
    }

    console.log("Recording updated successfully:", recordingData);

    return new NextResponse(
      JSON.stringify({
        id: summaryData[0].id,
      }),
      { status: 200 }
    );
  } catch (error) {
    if (error instanceof Error) {
      console.error(error);
      return new NextResponse(
        JSON.stringify({ status: "Error", message: error.message }),
        { status: 500 }
      );
    } else {
      console.error(error);
      return new NextResponse(
        JSON.stringify({
          status: "Error",
          message: "An unknown error occurred",
        }),
        { status: 500 }
      );
    }
  }
}

app/(apps)/audio/api/transcribe/route.ts.content:
import { NextResponse } from "next/server";
import { createClient } from "@/lib/utils/supabase/server";
import fetch from "node-fetch";
import { replicate } from "@/lib/clients/replicate";
import { revalidateTag } from "next/cache";

/**
 * API Route: Transcribes audio files using Replicate's Whisper model.
 *
 * **Process:**
 * 1. Authenticates the user.
 * 2. Fetches the audio file from the provided URL.
 * 3. Transcribes the audio using Replicate's Whisper model.
 * 4. Stores the transcription data in Supabase.
 * 5. Revalidates related cache tags.
 * 6. Returns the transcription ID and text.
 *
 * The transcription includes:
 * - Full text transcription
 * - Timestamped chunks for precise audio segment mapping
 * - Cache revalidation for UI consistency
 *
 * @param {Request} request - The incoming request object containing recordingId and audioUrl.
 * @returns {Promise<NextResponse>} JSON response containing the transcription details.
 */
export async function POST(request: any) {
  try {
    const supabase = await createClient();

    // Authenticate user
    const {
      data: { user },
    } = await supabase.auth.getUser();

    const userId = user?.id;

    if (!userId) {
      return NextResponse.json({
        error: "You must be logged in to transcribe audio",
      });
    }

    // Extract request parameters
    const requestBody = await request.json();
    const { recordingId, audioUrl } = requestBody;

    console.log("Transcribing audio for recording ID:", recordingId);
    console.log("Audio URL:", audioUrl);

    // Verify audio file accessibility
    const audioResponse = await fetch(audioUrl);
    if (!audioResponse.ok) {
      console.error("Failed to fetch audio file from URL:", audioUrl);
      return new NextResponse(
        JSON.stringify({
          error: "Failed to fetch audio file.",
        }),
        { status: 500 }
      );
    }

    // Transcribe audio using Replicate's Whisper model
    const output = (await replicate.run(
      "vaibhavs10/incredibly-fast-whisper:3ab86df6c8f54c11309d4d1f930ac292bad43ace52d10c80d87eb258b3c9f79c",
      {
        input: {
          task: "transcribe",
          audio: audioUrl,
          timestamp: "chunk",
          batch_size: 64,
        },
      }
    )) as { text: string; chunks: any[] };

    const modelUsed = "incredibly-fast-whisper";

    // Store transcription in database
    const { data, error } = await supabase
      .from("transcripts")
      .insert([
        {
          recording_id: recordingId,
          transcript: output.text,
          model: modelUsed,
          chunks: output.chunks,
        },
      ])
      .select();

    if (error) {
      console.error("Error inserting transcription:", error);
      return new NextResponse(
        JSON.stringify({
          error: "An error occurred while saving transcription data.",
        }),
        { status: 500 }
      );
    }

    // Revalidate cache tags
    revalidateTag(`recording_${recordingId}`);
    revalidateTag(`transcript_${recordingId}`);
    revalidateTag(`user_${userId}_recordings`);

    return new NextResponse(
      JSON.stringify({
        transcriptId: data[0].id,
        transcription: output.text,
      }),
      { status: 200 }
    );
  } catch (error) {
    console.error("Error processing transcription:", error);
    return new NextResponse(
      JSON.stringify({
        error:
          (error as Error).message ||
          "An error occurred during the transcription process.",
      }),
      { status: 500 }
    );
  }
}

app/(apps)/audio/api/upload/route.ts.content:
import { NextResponse } from "next/server";
import { createClient } from "@/lib/utils/supabase/server";
import { v4 as uuidv4 } from "uuid";
import { toolConfig } from "@/app/(apps)/audio/toolConfig";
import { uploadFile } from "@/lib/hooks/useFileUpload";
import { reduceUserCredits, getUserCredits } from "@/lib/db/mutations";

/**
 * API Route: Handles audio file uploads for the Audio app.
 *
 * **Process:**
 * 1. Authenticates the user.
 * 2. Extracts the audio file from the request.
 * 3. Generates a unique file name using UUID.
 * 4. Calls `uploadFile` to handle the upload.
 * 5. Stores metadata in the database.
 * 6. Reduces user credits if paywall is enabled.
 * 7. Returns the public URL, file path, and recording ID.
 *
 * @param {Request} request - The incoming request object.
 * @returns {Promise<NextResponse>} JSON response containing the uploaded audio details.
 */
export async function POST(request: Request) {
  const supabase = await createClient();

  // Authenticate user
  const {
    data: { user },
  } = await supabase.auth.getUser();

  const userId = user?.id;
  const userEmail = user?.email;

  if (!userId) {
    return NextResponse.json(
      { error: "You must be logged in to upload audio." },
      { status: 401 }
    );
  }

  try {
    const formData = await request.formData();
    const file = formData.get("file") as File | null;
    const uploadPath = "audio"; // Fixed upload path for audio files

    if (!file) {
      throw new Error("No audio file uploaded.");
    }

    // Check if paywall is enabled and validate user credits BEFORE processing
    if (toolConfig.paywall === true && userEmail) {
      const userCredits = await getUserCredits(userEmail);

      if (userCredits === null || userCredits === undefined) {
        return NextResponse.json(
          { error: "Unable to verify user credits" },
          { status: 400 }
        );
      }

      if (userCredits < toolConfig.credits) {
        return NextResponse.json(
          { 
            error: "Insufficient credits", 
            message: `You have ${userCredits} credits but need ${toolConfig.credits} credits to upload audio.`,
            creditsRequired: toolConfig.credits,
            creditsAvailable: userCredits
          },
          { status: 402 } // Payment Required
        );
      }
    }

    const uuid = uuidv4(); // Generate a UUID for file naming
    const fileName = `audio-${uuid}`; // Unique file name without extension

    // Call uploadFile to handle the upload
    const { url: publicUrl, path: filePath } = await uploadFile({
      file,
      uploadPath,
      fileName,
      contentType: file.type, // Use the original content type
      userId: user.id,
    });

    // Insert audio metadata into Supabase
    const { data, error: insertError } = await supabase
      .from("recordings")
      .insert([
        {
          file_url: publicUrl,
          user_id: userId,
        },
      ])
      .select();

    if (insertError) {
      console.error("Error inserting audio metadata:", insertError);
      return NextResponse.json(
        {
          error: "An error occurred while saving audio metadata.",
        },
        { status: 500 }
      );
    }

    // Reduce user credits if paywall is enabled
    if (toolConfig.paywall === true && userEmail) {
      await reduceUserCredits(userEmail, toolConfig.credits);
    }

    const recordingId = data[0].id;

    return NextResponse.json(
      {
        url: publicUrl,
        path: filePath,
        recordingId: recordingId,
      },
      { status: 200 }
    );
  } catch (error) {
    console.error("Error in audio upload:", error);
    return NextResponse.json(
      {
        error:
          (error as Error).message ||
          "An error occurred during the audio upload process.",
      },
      { status: 500 }
    );
  }
}

app/(apps)/chat/api/chat/route.ts.content:
/**
 * Chat API Route Handler
 * This file manages the chat functionality, including message processing, document creation,
 * web information retrieval, and credit system management.
 *
 * Main Features:
 * 1. Process chat messages between user and AI
 * 2. Create and update documents based on chat interactions
 * 3. Browse the internet for information
 * 4. Save chat history and manage chat sessions
 * 5. Credit System Management:
 *    - Track and manage user credits
 *    - Handle premium vs free model access
 *    - Control access to premium features
 *    - Automatic credit deduction
 *
 * Credit System Flow:
 * 1. Check user's available credits
 * 2. Validate feature access based on credits
 * 3. Calculate costs for:
 *    - Premium AI models
 *    - Web browsing feature
 * 4. Deduct credits for premium usage
 * 5. Return credit status in response
 *
 * Available Endpoints:
 * - POST /api/chat: Process new messages, generate AI responses, handle credits
 * - DELETE /api/chat?id={chatId}: Delete an entire chat session
 */

import {
  convertToModelMessages,
  UIMessage,
  streamText,
  CoreUserMessage,
  generateText,
  CoreMessage,
  ModelMessage,
  stepCountIs,
} from "ai";
import { createClient } from "@/lib/utils/supabase/server";
import { getChatById } from "@/lib/db/cached-queries";
import {
  saveChat,
  saveMessages,
  deleteChatById,
  reduceUserCredits,
} from "@/lib/db/mutations";
import { MessageRole } from "@/lib/types/supabase";
import {
  generateUUID,
  getMostRecentUserMessage,
  sanitizeResponseMessages,
} from "@/lib/ai/chat";
import { createSystemPrompt } from "@/app/(apps)/chat/prompt";
import { createTools, allTools, ToolsReturn } from "@/app/(apps)/chat/tools/";
import { customModel } from "@/lib/ai/ai-utils";
import { getUserCreditsQuery } from "@/lib/db/queries/general";
import {
  canUseConfiguration,
  FREE_MODELS,
} from "@/app/(apps)/chat/usage-limits";
import { AIModel, AI_MODEL_DISPLAY } from "@/lib/ai/models";

/**
 * Configuration Settings
 * - maxDuration: Maximum time (in seconds) allowed for API response
 * - customMiddleware: Custom settings for the AI model behavior
 */
export const maxDuration = 60;

/**
 * Generates a title for a new chat based on the user's first message
 * @param message - The first message from the user
 * @returns A generated title (max 80 characters)
 */
async function generateTitleFromUserMessage({
  message,
  modelId = "gpt-4o-mini",
}: {
  message: CoreUserMessage;
  modelId?: string;
}) {
  console.log("Generating title using model:", modelId);
  const { text: title } = await generateText({
    model: customModel(modelId, { isBrowseEnabled: false }),
    system: `\n
    - you will generate a short title based on the first message a user begins a conversation with
    - ensure it is not more than 80 characters long
    - the title should be a summary of the user's message
    - do not use quotes or colons`,
    prompt: JSON.stringify(message),
  });

  return title;
}

/**
 * Gets the current authenticated user
 * @throws Error if user is not authenticated
 */
async function getUser() {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) {
    throw new Error("User not found");
  }
  return user;
}

/**
 * Formats message content for database storage based on message type
 * Handles different message formats:
 * - User messages: Stored as plain text
 * - Tool messages: Stored as formatted tool results
 * - Assistant messages: Stored as text and tool calls
 */
function formatMessageContent(message: CoreMessage): string {
  // For user messages, store as plain text
  if (message.role === "user") {
    return typeof message.content === "string"
      ? message.content
      : JSON.stringify(message.content);
  }

  // For tool messages in v5
  if (message.role === "tool") {
    return JSON.stringify({
      type: "tool-result",
      toolCallId: (message as any).toolCallId,
      toolName: (message as any).toolName,
      result: message.content,
    });
  }

  // For assistant messages in v5
  if (message.role === "assistant") {
    const content = message.content;

    // If content is a string, return it as text
    if (typeof content === "string") {
      return JSON.stringify([{
        type: "text",
        text: content
      }]);
    }

    // If content is an array (v4 style), handle it
    if (Array.isArray(content)) {
      return JSON.stringify(
        content.map((item: any) => {
          if (item.type === "text") {
            return {
              type: "text",
              text: item.text
            };
          }
          if (item.type === "tool-call") {
            return {
              type: "tool-call",
              toolCallId: item.toolCallId,
              toolName: item.toolName,
              args: item.args
            };
          }
          return item;
        })
      );
    }

    // Otherwise return as-is
    return JSON.stringify(content);
  }

  return "";
}

/**
 * Main POST Handler
 * Processes incoming chat messages and generates AI responses
 *
 * Flow:
 * 1. Validates user authentication
 * 2. Creates or retrieves chat session
 * 3. Checks credit balance and feature access
 * 4. Processes message with AI
 * 5. Handles tool interactions (documents, internet)
 * 6. Manages credit deductions for premium features
 * 7. Saves chat history
 *
 * Credit Headers:
 * Returns 'x-credit-usage' with:
 * - cost: Credits used
 * - remaining: Available balance
 * - features: Premium features accessed
 *
 * @param request Contains chat ID, messages, and feature settings
 */
export async function POST(request: Request) {
  const {
    id,
    messages,
    selectedModelId,
    isBrowseEnabled,
  }: {
    id: string;
    messages: Array<UIMessage>;
    selectedModelId?: string;
    isBrowseEnabled: boolean;
  } = await request.json();

  console.log("Chat route params:", {
    id,
    selectedModelId,
    isBrowseEnabled,
    messageCount: messages.length,
  });

  const user = await getUser();

  if (!user?.email) {
    return new Response("Unauthorized", { status: 401 });
  }

  // Get the most recent user message for title generation
  const modelMessages = convertToModelMessages(messages);
  const userMessage = getMostRecentUserMessage(modelMessages);

  if (!userMessage || userMessage.role !== "user") {
    return new Response("No user message found", { status: 400 });
  }

  const supabase = await createClient();
  const credits = await getUserCreditsQuery(supabase, user.id);
  // Declare streamingData early, before the try block
  // const streamingData = new StreamData(); // Deprecated

  // Initial chat title logic (outside the main streaming response)
  let initialChatTitle = "New Chat";
  let isNewChat = false;

  try {
    // Chat title generation logic
    const chat = await getChatById(id);

    if (!chat) {
      const title = await generateTitleFromUserMessage({
        message: userMessage as CoreUserMessage,
        modelId: selectedModelId,
      });
      await saveChat({ id, userId: user.id, title });
      // Append chatReady signal AFTER saving the chat
      // streamingData.append({ chatReady: true }); // Moved to UI message stream
      initialChatTitle = title;
      isNewChat = true;
    } else if (chat.user_id !== user.id) {
      return new Response("Unauthorized", { status: 401 });
    } else if (chat.title === "New Chat") {
      // Update the title if it's still the default
      const title = await generateTitleFromUserMessage({
        message: userMessage as CoreUserMessage,
        modelId: selectedModelId,
      });
      await supabase
        .from("chats")
        .update({ title })
        .eq("id", id)
        .eq("user_id", user.id);
    }

    // Save the initial user message immediately
    await saveMessages({
      chatId: id,
      messages: [
        {
          id: generateUUID(),
          chat_id: id,
          role: userMessage.role as MessageRole,
          content: formatMessageContent(userMessage),
          created_at: new Date().toISOString(),
        },
      ],
    });

    const modelToUse = selectedModelId || "gpt-4o-mini";

    // Create tools and get active tool names
    const tools = createTools(user.id, modelToUse, isBrowseEnabled);
    const toolNames = Object.keys(tools);

    // Use all available tool names as active tools
    const activeTools = toolNames;

    console.log("Active tools:", activeTools, "Browse enabled:", isBrowseEnabled);

    // Credit check and usage
    const usageCheck = canUseConfiguration(credits, {
      modelId: selectedModelId as AIModel,
      isBrowseEnabled,
    });

    if (!usageCheck.canUse) {
      return new Response(
        JSON.stringify({
          error: "Insufficient credits",
          message: usageCheck.reason,
        }),
        { status: 402, headers: { "Content-Type": "application/json" } }
      );
    }

    // Calculate headers before creating the response stream
    const headers: Record<string, string> = {};
    if (usageCheck.requiredCredits > 0) {
      try {
        await reduceUserCredits(user.email!, usageCheck.requiredCredits);
        const updatedCredits = await getUserCreditsQuery(supabase, user.id);
        const creditUsageData = {
          cost: usageCheck.requiredCredits,
          remaining: updatedCredits,
          features: [
            !FREE_MODELS.includes(selectedModelId as any)
              ? "Premium Model"
              : null,
            isBrowseEnabled ? "Web Browsing" : null,
          ].filter(Boolean),
        };
        headers["x-credit-usage"] = JSON.stringify(creditUsageData);
      } catch (creditError) {
        console.error(
          "Failed to reduce credits or fetch updated count:",
          creditError
        );
        headers["x-credit-error"] = "Failed to process credits";
      }
    }

    const systemPrompt = createSystemPrompt(isBrowseEnabled);

    console.log("[CHAT ROUTE] Tool names in tools object:", Object.keys(tools));

    const result = streamText({
      model: customModel(modelToUse, { isBrowseEnabled }),
      system: systemPrompt,
      messages: modelMessages,
      activeTools,
      tools: tools as any,
      onFinish: async ({ response }) => {
        // Save messages after completion
        if (user && user.id && response) {
          try {
            const responseMessages = response.messages || [];

            // Log tool results to debug web search
            const toolMessages = responseMessages.filter(m => m.role === 'tool');
            console.log('[CHAT ROUTE] Tool messages found:', toolMessages.length);
            toolMessages.forEach((msg) => {
              console.log('[CHAT ROUTE] Tool message:', {
                role: msg.role,
                toolName: (msg as any).toolName,
                content: typeof msg.content === 'string' ? 
                  msg.content.substring(0, 200) : msg.content
              });
            });

            // Also log assistant messages to see tool calls
            const assistantMessages = responseMessages.filter(m => m.role === 'assistant');
            assistantMessages.forEach((msg) => {
              if (Array.isArray(msg.content)) {
                const toolCalls = msg.content.filter((c: any) => c.type === 'tool-call');
                if (toolCalls.length > 0) {
                  console.log('[CHAT ROUTE] Assistant tool calls:', toolCalls);
                }
              }
            });

            const responseMessagesWithoutIncompleteToolCalls =
              sanitizeResponseMessages(responseMessages);

            // --- DE-DUPLICATION START ---
            const uniqueMessagesMap = new Map<string, any>();
            responseMessagesWithoutIncompleteToolCalls.forEach((message) => {
              // Format content first to create a reliable unique key
              const formattedContent = formatMessageContent(message);
              const uniqueKey = `${message.role}-${JSON.stringify(
                formattedContent
              )}`;

              if (!uniqueMessagesMap.has(uniqueKey)) {
                // Generate ID only for unique messages before adding to map
                const messageId = generateUUID();
                uniqueMessagesMap.set(uniqueKey, {
                  id: messageId,
                  chat_id: id,
                  role: message.role as MessageRole,
                  content: formattedContent,
                  created_at: new Date().toISOString(),
                });
              }
            });

            // Extract the unique message objects from the map
            const finalMessagesToSave = Array.from(uniqueMessagesMap.values());

            // Save only the unique messages
            await saveMessages({
              chatId: id,
              messages: finalMessagesToSave,
            });
          } catch (error) {
            console.error("Failed to save chat:", error);
          }
        }
      }
    });

    // Special handling for provider-specific search features
    const isOpenAIResponsesAPI = modelToUse.startsWith("gpt") || modelToUse.startsWith("o4");
    const isGoogleModel = modelToUse.startsWith("gemini");

    if (isOpenAIResponsesAPI && isBrowseEnabled && (result as any).sources) {
      console.log('[CHAT ROUTE] OpenAI Responses API detected with sources');

      // Wait for the sources to be available
      (result as any).sources.then((sources: any) => {
        console.log('[CHAT ROUTE] OpenAI sources available:', sources);
      }).catch((error: any) => {
        console.error('[CHAT ROUTE] Failed to get OpenAI sources:', error);
      });
    }

    if (isGoogleModel && isBrowseEnabled) {
      console.log('[CHAT ROUTE] Google model with search detected');
      // Google might include grounding metadata in the response
      if ((result as any).experimental_providerMetadata) {
        console.log('[CHAT ROUTE] Google provider metadata:', (result as any).experimental_providerMetadata);
      }
    }

    // Regular response - the UI will handle tool results
    return result.toUIMessageStreamResponse({
      headers,
      originalMessages: messages,
      messageMetadata: ({ part }) => {
        // Send credit usage with finish event
        if (part.type === 'finish' && headers["x-credit-usage"]) {
          try {
            const creditUsage = JSON.parse(headers["x-credit-usage"] as string);
            return { creditUsage };
          } catch (e) {
            console.error('Failed to parse credit usage', e);
          }
        }
      }
    });
  } catch (error) {
    console.error("Error in chat route:", error);
    // This catch block might need adjustment as the main logic is now within UI message stream
    // For now, let's keep the existing fallback for 'Chat ID already exists'
    if (error instanceof Error && error.message === "Chat ID already exists") {
      // This case should be less likely now with the check moved up, but keep as fallback
      console.warn(
        "Caught 'Chat ID already exists' outside main stream logic - check flow."
      );
      return new Response("Conflict: Chat ID potentially already exists", {
        status: 409,
      });
    } else {
      // For other errors caught *before* UI message stream
      return new Response("Internal Server Error", { status: 500 });
    }
  }
}

/**
 * DELETE Handler
 * Removes an entire chat session and its messages
 *
 * Security:
 * - Verifies user ownership of chat
 * - Only allows deletion of user's own chats
 *
 * @param request Contains chat ID to delete
 */
export async function DELETE(request: Request) {
  const { searchParams } = new URL(request.url);
  const chatId = searchParams.get("id");

  if (!chatId) {
    return new Response("Chat ID is required", { status: 400 });
  }

  const user = await getUser();
  if (!user) {
    return new Response("Unauthorized", { status: 401 });
  }

  try {
    // First verify that the chat belongs to the user
    const chat = await getChatById(chatId);
    if (!chat || chat.user_id !== user.id) {
      return new Response("Chat not found or unauthorized", { status: 403 });
    }

    // Delete the chat (messages will be cascade deleted due to foreign key constraint)
    await deleteChatById(chatId, user.id);

    return new Response("Chat deleted successfully", { status: 200 });
  } catch (error) {
    console.error("Failed to delete chat:", error);
    return new Response("Failed to delete chat", { status: 500 });
  }
}

