import { NextRequest, NextResponse } from "next/server";
import s3 from "@/lib/clients/cloudflare";
import { DeleteObjectCommand } from "@aws-sdk/client-s3";
import { createClient } from "@/lib/utils/supabase/server";
import { authMiddleware } from "@/lib/middleware/authMiddleware";
import { revalidateTag } from "next/cache";

/**
 * API Route: Handles PDF document deletion.
 *
 * **Features:**
 * - Deletes PDF files from cloud storage
 * - Removes document metadata from database
 * - Handles authentication and authorization
 * - Cleans up associated resources
 * - Revalidates cache tags for UI consistency
 *
 * **Process:**
 * 1. Authenticates the user
 * 2. Retrieves document metadata from database
 * 3. Deletes file from cloud storage
 * 4. Removes database entries
 * 5. Revalidates related cache tags
 *
 * **Security:**
 * - Requires user authentication
 * - Validates document ownership
 * - Ensures complete cleanup of all resources
 *
 * @param {NextRequest} request - Contains documentId for deletion
 * @returns {Promise<NextResponse>} Confirmation of successful deletion
 */
export async function POST(request: NextRequest) {
  // Authenticate user
  const authResponse = await authMiddleware(request);
  if (authResponse.status === 401) return authResponse;

  const supabase = await createClient();
  const { documentId } = await request.json();

  // Get the user ID properly from Supabase
  const {
    data: { user },
  } = await supabase.auth.getUser();
  const userId = user?.id;

  if (!userId) {
    return NextResponse.json(
      { error: "User not authenticated" },
      { status: 401 }
    );
  }

  // Retrieve document metadata and verify ownership
  const { data: document, error } = await supabase
    .from("pdf_documents")
    .select("file_url")
    .eq("id", documentId)
    .eq("user_id", userId)
    .single();

  if (error || !document) {
    return NextResponse.json({ error: "Document not found" }, { status: 404 });
  }

  // Prepare cloud storage deletion
  const deleteCommand = new DeleteObjectCommand({
    Bucket: process.env.STORAGE_BUCKET,
    Key: document.file_url.split(`${process.env.STORAGE_PUBLIC_URL}/`)[1],
  });

  try {
    // Delete from cloud storage and database
    await s3.send(deleteCommand);
    await supabase
      .from("pdf_documents")
      .delete()
      .eq("id", documentId)
      .eq("user_id", userId);

    // Revalidate cache tags with correct userId
    revalidateTag(`pdf_document_${documentId}`);
    revalidateTag(`user_${userId}_pdf_documents`);

    return NextResponse.json({ success: true }, { status: 200 });
  } catch (error) {
    console.error("Error deleting document:", error);
    return NextResponse.json(
      { error: "Failed to delete document" },
      { status: 500 }
    );
  }
}

app/(apps)/pdf/api/externaldoc/route.ts.content:
import { NextRequest, NextResponse } from "next/server";
import { createClient } from "@/lib/utils/supabase/server";

/**
 * API Route: Handles external PDF document registration.
 *
 * **Features:**
 * - Registers external PDF URLs in the system
 * - Enforces document limits per user
 * - Maintains document metadata without file storage
 * - Supports integration with external document sources
 *
 * **Process:**
 * 1. Authenticates the user
 * 2. Validates user's document count limit
 * 3. Registers external document URL
 * 4. Creates document metadata entry
 *
 * **Limitations:**
 * - Maximum 10 documents per user
 * - Requires valid external URL
 * - URL must point to accessible PDF
 *
 * @param {NextRequest} request - Contains URL and fileName for external document
 * @returns {Promise<NextResponse>} Document ID and URL confirmation
 */
export async function POST(request: NextRequest) {
  const supabase = await createClient();
  const { url, fileName } = await request.json();

  // Authenticate user
  const {
    data: { user },
  } = await supabase.auth.getUser();

  const userId = user?.id;

  if (!userId) {
    return NextResponse.json({
      error: "You must be logged in to ingest data",
    });
  }

  // Check document limit
  const { data: docCount, error: countError } = await supabase
    .from("pdf_documents")
    .select("id", { count: "exact" })
    .eq("user_id", userId);

  if (countError || (docCount && docCount.length > 10)) {
    return NextResponse.json({
      error: "You have reached the maximum (10) number of documents.",
    });
  }

  try {
    // Register external document
    const { data, error: insertError } = await supabase
      .from("pdf_documents")
      .insert([
        {
          file_url: url,
          file_name: fileName,
          user_id: userId,
          size: null, // Size unknown for external documents
        },
      ])
      .select();

    if (insertError) {
      console.error("Error inserting document metadata:", insertError);
      return new NextResponse(
        JSON.stringify({
          error: "An error occurred while saving document metadata.",
        }),
        { status: 500 }
      );
    }

    return new NextResponse(JSON.stringify({ documentId: data[0].id, url }), {
      status: 200,
    });
  } catch (error) {
    console.error("Error in URL document addition:", error);
    return new NextResponse(
      JSON.stringify({
        error:
          (error as Error).message ||
          "An error occurred during the URL document addition process.",
      }),
      { status: 500 }
    );
  }
}

app/(apps)/pdf/api/upload/route.ts.content:
import { NextResponse } from "next/server";
import { createClient } from "@/lib/utils/supabase/server";
import { v4 as uuidv4 } from "uuid";
import { reduceUserCredits, getUserCredits } from "@/lib/db/mutations";
import { toolConfig } from "@/app/(apps)/pdf/toolConfig";
import { uploadFile } from "@/lib/hooks/useFileUpload";

/**
 * API Route: Handles PDF file uploads for the PDF app.
 *
 * **Process:**
 * 1. Authenticates the user.
 * 2. Checks if the user has reached their document limit.
 * 3. Extracts the PDF file from the request.
 * 4. Generates a unique file name using UUID.
 * 5. Calls `uploadFile` to handle the upload.
 * 6. Stores document metadata in the database.
 * 7. Reduces user credits if paywall is enabled.
 * 8. Returns the public URL, file path, and document ID.
 *
 * @param {Request} request - The incoming request object.
 * @returns {Promise<NextResponse>} JSON response containing the uploaded document details.
 */
export async function POST(request: Request) {
  const supabase = await createClient();

  // Authenticate user
  const {
    data: { user },
  } = await supabase.auth.getUser();

  const userId = user?.id;
  const userEmail = user?.email;

  if (!userId) {
    return NextResponse.json(
      { error: "You must be logged in to upload documents." },
      { status: 401 }
    );
  }

  // Check if user has reached the maximum number of documents
  const { count, error: countError } = await supabase
    .from("pdf_documents")
    .select("*", { count: "exact", head: true })
    .eq("user_id", userId);
  if (countError) {
    console.error("Error checking document count:", countError);
    return NextResponse.json(
      {
        error: "An error occurred while checking your document count.",
      },
      { status: 500 }
    );
  }

  if (count && count >= 10) {
    return NextResponse.json(
      {
        error: "You have reached the maximum (10) number of documents.",
      },
      { status: 400 }
    );
  }

  try {
    const formData = await request.formData();
    const file = formData.get("file") as File | null;
    const uploadPath = "documents"; // Fixed upload path for documents

    if (!file) {
      throw new Error("No document file uploaded.");
    }

    // Check if paywall is enabled and validate user credits BEFORE processing
    if (toolConfig.paywall === true && userEmail) {
      const userCredits = await getUserCredits(userEmail);

      if (userCredits === null || userCredits === undefined) {
        return NextResponse.json(
          { error: "Unable to verify user credits" },
          { status: 400 }
        );
      }

      if (userCredits < toolConfig.credits) {
        return NextResponse.json(
          { 
            error: "Insufficient credits", 
            message: `You have ${userCredits} credits but need ${toolConfig.credits} credits to upload a document.`,
            creditsRequired: toolConfig.credits,
            creditsAvailable: userCredits
          },
          { status: 402 } // Payment Required
        );
      }
    }

    const uuid = uuidv4(); // Generate a UUID for file naming
    const fileName = `document-${uuid}`; // Unique file name without extension
    const fileSizeMB = (file.size / (1024 * 1024)).toFixed(2); // Convert size to MB

    console.log(`File Size: ${fileSizeMB} MB`);
    console.log("Uploading document...");

    // Call uploadFile to handle the upload
    const { url: publicUrl, path: filePath } = await uploadFile({
      file,
      uploadPath,
      fileName,
      contentType: file.type, // Use the original content type
      userId,
    });

    console.log("Inserting document metadata...");

    // Insert document metadata into Supabase
    const { data, error: insertError } = await supabase
      .from("pdf_documents")
      .insert([
        {
          file_url: publicUrl,
          file_name: file.name,
          user_id: userId,
          size: parseFloat(fileSizeMB),
        },
      ])
      .select();

    if (insertError) {
      console.error("Error inserting document metadata:", insertError);
      return NextResponse.json(
        {
          error: "An error occurred while saving document metadata.",
        },
        { status: 500 }
      );
    }

    // Reduce user credits if paywall is enabled
    if (toolConfig.paywall === true && userEmail) {
      await reduceUserCredits(userEmail, toolConfig.credits);
    }

    const documentId = data[0].id;

    return NextResponse.json(
      {
        url: publicUrl,
        path: filePath,
        documentId: documentId,
      },
      { status: 200 }
    );
  } catch (error) {
    console.error("Error in file upload:", error);
    return NextResponse.json(
      {
        error:
          (error as Error).message ||
          "An error occurred during the file upload process.",
      },
      { status: 500 }
    );
  }
}

app/(apps)/pdf/api/vectorize/route.ts.content:
import { NextRequest, NextResponse } from "next/server";
import { createClient } from "@/lib/utils/supabase/server";
import { RecursiveCharacterTextSplitter } from "langchain/text_splitter";
import { OpenAIEmbeddings } from "@langchain/openai";
import { Document } from "langchain/document";
import { PDFLoader } from "@langchain/community/document_loaders/fs/pdf";
import { authMiddleware } from "@/lib/middleware/authMiddleware";
import { revalidateTag } from "next/cache";

/**
 * API Route: Handles PDF vectorization for semantic search capabilities.
 *
 * **Features:**
 * - Converts PDF content into vector embeddings using OpenAI
 * - Splits documents into manageable chunks for better search
 * - Stores embeddings in Supabase for vector similarity search
 * - Maintains page numbers and document references
 * - Sanitizes text to remove problematic characters
 * - Revalidates cache tags for UI consistency
 *
 * **Process:**
 * 1. Authenticates the user
 * 2. Fetches PDF from provided URL
 * 3. Splits document into chunks using LangChain
 * 4. Generates embeddings using OpenAI
 * 5. Stores embeddings with metadata in Supabase
 * 6. Revalidates related cache tags
 *
 * **Technical Details:**
 * - Chunk size: 1000 characters
 * - Chunk overlap: 200 characters
 * - Uses RecursiveCharacterTextSplitter for intelligent splitting
 * - Maintains document-chunk-page relationships
 *
 * @param {NextRequest} request - Contains fileUrl and documentId
 * @returns {Promise<NextResponse>} Confirmation of successful vectorization
 */

type DocumentMetadata = {
  document_id: any;
  page: number;
};

/**
 * Sanitizes text by removing problematic characters
 * - Removes null characters
 * - Removes non-printable ASCII characters
 * - Preserves common whitespace characters
 */
function sanitizeText(text: string): string {
  return text
    .replace(/\u0000/g, "") // Remove null characters
    .replace(/[^\x20-\x7E\n\r\t]/g, "") // Remove non-printable ASCII characters
    .trim();
}

/**
 * Batch size for processing and inserting embeddings
 * - Prevents Supabase statement timeout errors
 * - Reduces memory usage for large documents
 * - Recommended: 100 chunks per batch for optimal performance
 * - Adjust based on your Supabase plan and document size
 */
const BATCH_SIZE = 100;

export async function POST(request: NextRequest) {
  // Check if the user is authenticated
  const authResponse = await authMiddleware(request);
  if (authResponse.status === 401) return authResponse;

  const supabase = await createClient();
  const { fileUrl, documentId } = await request.json();
  const userId = (request as any).user.id; // Get userId from middleware-enhanced request

  if (!fileUrl || typeof fileUrl !== "string") {
    return NextResponse.json(
      { error: "A valid file URL is required" },
      { status: 400 }
    );
  }

  if (!documentId) {
    return NextResponse.json(
      { error: "Document ID is required" },
      { status: 400 }
    );
  }

  async function fetchDocumentsFromUrl(url: string) {
    try {
      const response = await fetch(url);
      if (!response.ok)
        throw new Error(`Failed to fetch PDF: ${response.statusText}`);

      const buffer = await response.arrayBuffer();

      // Load the PDF with improved parsing (splitting by page)
      const loader = new PDFLoader(new Blob([buffer]), {
        splitPages: true,
        parsedItemSeparator: "",
      });

      const rawDocs = await loader.load();

      // Set up the text splitter with additional separators to help preserve whole sentences/paragraphs
      const textSplitter = new RecursiveCharacterTextSplitter({
        chunkSize: 1000,
        chunkOverlap: 200,
        separators: ["\n\n", "\n", " "], // try to break at natural boundaries
      });

      const splitDocs = await textSplitter.splitDocuments(rawDocs);

      // Filter out any chunks that are too short to be meaningful,
      // then create new Documents that include page number metadata.
      return splitDocs
        .filter((doc) => doc.pageContent.trim().length > 20)
        .map(
          (doc) =>
            new Document<DocumentMetadata>({
              pageContent: sanitizeText(doc.pageContent),
              metadata: {
                document_id: documentId,
                page: doc.metadata.loc?.pageNumber || 1,
              },
            })
        );
    } catch (error) {
      console.error("Error fetching documents from URL:", error);
      throw error;
    }
  }

  try {
    const documents = await fetchDocumentsFromUrl(fileUrl);
    const embeddings = new OpenAIEmbeddings();

    /**
     * Process and insert documents in batches to avoid Supabase timeouts
     *
     * Why batching is necessary:
     * 1. Supabase has a default statement timeout (typically 30s)
     * 2. Large PDFs can generate hundreds/thousands of embeddings
     * 3. Single transaction with many insertions can exceed timeout
     *
     * Batch processing:
     * - Splits documents into chunks of BATCH_SIZE
     * - Processes embeddings for each batch
     * - Inserts each batch separately into Supabase
     * - Continues even if document has hundreds of pages
     */
    for (let i = 0; i < documents.length; i += BATCH_SIZE) {
      const batch = documents.slice(i, i + BATCH_SIZE);

      // Generate embeddings for current batch only
      const batchEmbeddings = await embeddings.embedDocuments(
        batch.map((doc) => doc.pageContent)
      );

      // Prepare data for current batch
      const batchEmbeddingsData = batch.map((doc, index) => ({
        document_id: documentId,
        content: doc.pageContent,
        embedding: batchEmbeddings[index],
        metadata: doc.metadata,
      }));

      // Insert current batch to Supabase
      const { error: supabaseError } = await supabase
        .from("embeddings")
        .insert(batchEmbeddingsData);

      if (supabaseError) {
        console.error("Supabase insertion error:", supabaseError);
        throw supabaseError;
      }
    }

    // Revalidate cache tags
    revalidateTag(`pdf_document_${documentId}`);
    revalidateTag(`user_${userId}_pdf_documents`);

    return NextResponse.json({
      text: "Successfully embedded PDF",
      id: documentId,
    });
  } catch (error) {
    console.error("Error in POST function:", error);
    return NextResponse.json(
      { error: "Failed to ingest your data" },
      { status: 500 }
    );
  }
}

