interface Stack {
  id: string;
  slug: string;
  title: string;
  description: string;
}

interface StackSession {
  id: string;
  title: string;
  status: string;
  created_at: string;
  stack: {
    slug: string;
    title: string;
  };
}

export function StackSidebar() {
