"use client";

import { useParams } from "next/navigation";
import { useEffect, useState } from "react";
import { StackChat } from "@/components/stacks/StackChat";
import { ProgressHeader } from "@/components/stacks/ProgressHeader";

interface StackSession {
  id: string;
  title: string;
  status: string;
  current_index: number;
  stack: {
    slug: string;
    title: string;
    questions: Array<{
      index: number;
      key: string;
      text: string;
    }>;
  };
}

export default function StackSessionPage() {
  const params = useParams();
  const [session, setSession] = useState<StackSession | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    fetchSession();
  }, [params.sessionId]);

  const fetchSession = async () => {
    try {
      setLoading(true);
      const response = await fetch(`/stacks/api/session?sessionId=${params.sessionId}`);

      if (!response.ok) {
        throw new Error("Failed to fetch session");
      }

      const sessionData = await response.json();
      setSession(sessionData);
      setError(null);
    } catch (err) {
      setError(err instanceof Error ? err.message : "An error occurred");
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex-1 flex items-center justify-center">
        <div className="text-center">
          <div className="loading loading-spinner loading-lg mb-4"></div>
          <p>Loading your session...</p>
        </div>
      </div>
    );
  }

  if (error || !session) {
    return (
      <div className="flex-1 flex items-center justify-center">
        <div className="text-center">
          <div className="text-6xl mb-4">⚠️</div>
          <h2 className="text-xl font-semibold text-error mb-2">
            {error || "Session not found"}
          </h2>
          <p className="text-base-content/70 mb-4">
            Please try again or start a new session.
          </p>
          <button 
            onClick={() => window.history.back()}
            className="px-4 py-2 bg-primary text-primary-content rounded-lg"
          >
            Go Back
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="flex-1 flex flex-col">
      <ProgressHeader
        title={session.title}
        currentIndex={session.current_index}
        totalQuestions={session.stack.questions.length}
        status={session.status}
      />

      <StackChat
        session={session}
        onSessionUpdate={setSession}
      />
    </div>
  );
}

app/stacks/[slug]/new/page.tsx.content:
"use client";

import { useParams, useRouter } from "next/navigation";
import { useState, useEffect } from "react";

interface Stack {
  id: string;
  slug: string;
  title: string;
  description: string;
  questions: Array<{ index: number; key: string; text: string }>;
}

export default function NewStackPage() {
  const params = useParams();
  const router = useRouter();
  const [title, setTitle] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [stack, setStack] = useState<Stack | null>(null);
  const [loadingStack, setLoadingStack] = useState(true);

  useEffect(() => {
    fetchStackInfo();
  }, [params.slug]);

  const fetchStackInfo = async () => {
    try {
      const response = await fetch("/stacks/api/stacks");
      if (response.ok) {
        const stacks = await response.json();
        const currentStack = stacks.find((s: Stack) => s.slug === params.slug);
        setStack(currentStack || null);
      }
    } catch (error) {
      console.error("Error fetching stack info:", error);
    } finally {
      setLoadingStack(false);
    }
  };

  const handleStart = async () => {
    if (!title.trim()) return;

    setIsLoading(true);

    try {
      const response = await fetch("/stacks/api/session", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          stackSlug: params.slug,
          title: title.trim(),
        }),
      });

      if (!response.ok) {
        throw new Error("Failed to create session");
      }

      const session = await response.json();
      router.push(`/stacks/${params.slug}/${session.id}`);
    } catch (error) {
      console.error("Error creating session:", error);
      alert("Failed to start stack session. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  if (loadingStack) {
    return (
      <div className="flex-1 flex items-center justify-center p-8">
        <div className="text-center">
          <div className="loading loading-spinner loading-lg mb-4"></div>
          <p>Loading stack information...</p>
        </div>
      </div>
    );
  }

  if (!stack) {
    return (
      <div className="flex-1 flex items-center justify-center p-8">
        <div className="text-center">
          <div className="text-6xl mb-4">❌</div>
          <h2 className="text-2xl font-bold mb-2">Stack Not Found</h2>
          <p className="text-base-content/70 mb-4">The requested stack doesn't exist.</p>
          <button 
            onClick={() => router.push('/stacks')}
            className="px-4 py-2 bg-primary text-primary-content rounded-lg"
          >
            Back to Stacks
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="flex-1 flex items-center justify-center p-8">
      <div className="max-w-md w-full space-y-6">
        <div className="text-center">
          <div className="text-6xl mb-4">🙏</div>
          <h1 className="text-3xl font-bold text-base-content mb-2">
            {stack.title}
          </h1>
          <p className="text-base-content/70 mb-4">
            {stack.description}
          </p>
          <div className="text-sm text-base-content/60 mb-6">
            📝 {stack.questions.length} questions • ~{Math.ceil(stack.questions.length * 2)} minutes
          </div>
        </div>

        <div className="space-y-4">
          <div>
            <label htmlFor="title" className="block text-sm font-medium text-base-content mb-2">
              Session Title
            </label>
            <input
              id="title"
              type="text"
              placeholder="e.g., Reflecting on my relationship with..."
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              className="w-full px-3 py-2 border border-base-300 rounded-lg bg-base-100 text-base-content focus:outline-none focus:ring-2 focus:ring-primary"
              disabled={isLoading}
              maxLength={100}
            />
            <div className="text-xs text-base-content/50 mt-1">
              Give your session a meaningful title to help you remember it later
            </div>
          </div>

          <button
            onClick={handleStart}
            disabled={!title.trim() || isLoading}
            className="w-full py-3 bg-primary text-primary-content rounded-lg hover:bg-primary/90 transition-colors disabled:opacity-50 disabled:cursor-not-allowed font-medium"
          >
            {isLoading ? (
              <span className="flex items-center justify-center">
                <span className="loading loading-spinner loading-sm mr-2"></span>
                Starting...
              </span>
            ) : (
              "Begin Stack"
            )}
          </button>
        </div>

        <div className="text-center">
          <button 
            onClick={() => router.push('/stacks')}
            className="text-sm text-base-content/60 hover:text-base-content"
          >
            ← Back to all stacks
          </button>
        </div>
      </div>
    </div>
  );
}

app/stacks/api/answer/route.ts.content:
import { NextRequest, NextResponse } from "next/server";
import { getSessionWithStack, upsertAnswer, updateSessionProgress } from "@/lib/db-connection";

export async function POST(request: NextRequest) {
  try {
    const { sessionId, questionIndex, answer } = await request.json();

    if (!sessionId || questionIndex === undefined || !answer) {
      return NextResponse.json(
        { error: "Missing required fields" },
        { status: 400 }
      );
    }

    // Get session from database with stack information
    console.log(`🔍 [ANSWER] Looking for session: ${sessionId}`);

    const { data: session, error: sessionError } = await getSessionWithStack(sessionId);

    if (sessionError || !session) {
      // Check if it's an invalid UUID format error
      if (sessionError && sessionError.type === "INVALID_UUID") {
        console.error(`❌ [ANSWER] Invalid session ID format: ${sessionId}`);
        return NextResponse.json(
          { error: "Invalid session ID format" },
          { status: 400 }
        );
      }

      console.error(`❌ [ANSWER] Session not found: ${sessionId}`, sessionError);
      return NextResponse.json(
        { error: "Session not found" },
        { status: 404 }
      );
    }

    console.log(`✅ [ANSWER] Session found: ${sessionId}`);

    // Get current question from stack
    const questions = session.stacks.questions;
    const question = questions[questionIndex];

    if (!question) {
      return NextResponse.json(
        { error: "Question not found" },
        { status: 404 }
      );
    }

    // Save answer using upsert function
    const { data: answerData, error: answerError } = await upsertAnswer(
      sessionId,
      questionIndex,
      question.key,
      question.text,
      answer
    );

    if (answerError) {
      console.error(`❌ [ANSWER] Failed to save answer:`, answerError);
      return NextResponse.json(
        { error: "Failed to save answer" },
        { status: 500 }
      );
    }

    // Update session progress
    const nextIndex = questionIndex + 1;
    const isCompleted = nextIndex >= questions.length;

    const { error: updateError } = await updateSessionProgress(
      sessionId,
      nextIndex,
      isCompleted ? 'completed' : 'in_progress'
    );

    if (updateError) {
      console.error(`⚠️ [ANSWER] Failed to update session progress:`, updateError);
      // Don't fail the request as answer was saved successfully
    }

    console.log(`✅ [ANSWER] Answer saved for session: ${sessionId}, Question: ${questionIndex}, Current progress: ${nextIndex}/${questions.length}`);

    return NextResponse.json({
      success: true,
      current_index: nextIndex,
      completed: isCompleted
    });
  } catch (error) {
    console.error("Error saving answer:", error);
    return NextResponse.json(
      { error: "Failed to save answer" },
      { status: 500 }
    );
  }
}

